// ═══════════════════════════════════════════════════════════════════
// Safe Console - Prevent EPIPE errors on startup + Performance Mode
// ═══════════════════════════════════════════════════════════════════
const IS_DEBUG = process.env.ELOS_DEBUG === 'true';
const LOG_LEVEL = process.env.LOG_LEVEL || 'error';

const safeLog = (...args) => {
  // في وضع الإنتاج، سجل فقط الرسائل المهمة (التي تبدأ بـ [DB] أو [BACKUP])
  if (!IS_DEBUG && LOG_LEVEL === 'error') {
    const firstArg = String(args[0] || '');
    // سجل فقط أخطاء ورسائل البدء المهمة
    if (!firstArg.includes('[DB] 🎉') && !firstArg.includes('[BACKUP] ✅') && !firstArg.includes('Error')) {
      return; // تخطي التسجيل لتحسين الأداء
    }
  }
  try {
    if (process.stdout && process.stdout.writable) {
      console.log(...args);
    }
  } catch (e) {
    // Ignore EPIPE errors
  }
};

const safeError = (...args) => {
  try {
    if (process.stderr && process.stderr.writable) {
      console.error(...args);
    }
  } catch (e) {
    // Ignore EPIPE errors
  }
};

// ═══════════════════════════════════════════════════════════════════
// IMPORTANT NOTES - CLIENT BALANCE CALCULATION
// ═══════════════════════════════════════════════════════════════════
// تم تحديث نظام حساب رصيد العملاء ليصبح ديناميكياً ودقيقاً:
//
// ✅ الرصيد يُحسب من المصادر التالية:
//    1. الرصيد الافتتاحي: clients.opening_balance (ديون قبل النظام)
//    2. ديون المبيعات: SUM(sell_price - discount - paid_now)
//       WHERE status='completed'
//    3. ديون الإكسسوارات: SUM(total_price - paid_amount) FROM accessory_movements
//    4. ديون قطع الغيار: SUM(total_price - paid_amount) FROM repair_parts_pos_sales
//    5. المدفوعات المنفصلة: من safe_transactions و cash_ledger
//
// ✅ المعادلة النهائية:
//    balance = (الرصيد الافتتاحي) + (ديون المبيعات) + (ديون الإكسسوارات)
//              + (ديون قطع الغيار) - (المدفوعات المنفصلة)
//
// ✅ عمود clients.balance أصبح DEPRECATED ولا يُستخدم
//
// ✅ الفواتير الملغاة (cancelled) والمرتجعة (returned) لا تُحسب
//
// ✅ الرصيد الافتتاحي يُحفظ في clients.opening_balance (Migration 50)
//
// ═══════════════════════════════════════════════════════════════════
// CASH LEDGER REF PATTERNS (للتصفية - استخدم ref فقط، ليس note)
// ═══════════════════════════════════════════════════════════════════
//
// | النوع                  | ref Pattern              | مثال                     |
// |------------------------|--------------------------|--------------------------|
// | دفعة من عميل           | client_payment_{id}      | client_payment_42        |
// | دفعة مع فاتورة بيع     | sale                     | sale                     |
// | مرتجع بيع              | return                   | return                   |
// | إلغاء بيع              | cancel                   | cancel                   |
// | دفع لمورد              | supplier_payment_{id}    | supplier_payment_15      |
// | رواتب                  | salary                   | salary                   |
// | مصاريف يدوية           | manual                   | manual                   |
//
// ⚠️ IMPORTANT: استخدم ref للتصفية دائماً، note للعرض فقط
//
// ═══════════════════════════════════════════════════════════════════

