// Migration 22: Update supplier_transactions CHECK constraint to include 'return' type
try {
  // SQLite لا يدعم ALTER TABLE لتعديل CHECK constraints مباشرة
  // لذلك نحتاج إعادة إنشاء الجدول
  const tableInfo = db.prepare("PRAGMA table_info(supplier_transactions)").all();
  const hasReturnType = db.prepare(`
    SELECT sql FROM sqlite_master WHERE type='table' AND name='supplier_transactions'
  `).get();

  if (hasReturnType && hasReturnType.sql && !hasReturnType.sql.includes("'return'")) {
    console.log('[DB] Migration 22: Updating supplier_transactions to support return type...');

    // 1. إنشاء جدول مؤقت جديد مع CHECK constraint محدث
    db.exec(`
      CREATE TABLE IF NOT EXISTS supplier_transactions_new(
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        supplier_id INTEGER NOT NULL,
        type TEXT NOT NULL CHECK(type IN ('purchase','payment','opening_balance','adjustment','return')),
        amount REAL NOT NULL DEFAULT 0,
        balance_before REAL DEFAULT 0,
        balance_after REAL DEFAULT 0,
        reference_type TEXT,
        reference_id INTEGER,
        payment_method TEXT DEFAULT 'cash',
        notes TEXT,
        created_by TEXT DEFAULT 'system',
        created_at TEXT NOT NULL DEFAULT (datetime('now', 'localtime')),
        FOREIGN KEY(supplier_id) REFERENCES suppliers(id)
      )
    `);

    // 2. نسخ البيانات من الجدول القديم
    db.exec(`
      INSERT INTO supplier_transactions_new
      SELECT * FROM supplier_transactions
    `);

    // 3. حذف الجدول القديم
    db.exec(`DROP TABLE supplier_transactions`);

    // 4. إعادة تسمية الجدول الجديد
    db.exec(`ALTER TABLE supplier_transactions_new RENAME TO supplier_transactions`);

    // 5. إعادة إنشاء الـ index
    db.exec(`CREATE INDEX IF NOT EXISTS idx_supplier_transactions_supplier ON supplier_transactions(supplier_id)`);

    console.log('[DB] ✅ Migration 22: supplier_transactions updated to support return type');
  } else {
    console.log('[DB] ✅ Migration 22: supplier_transactions already supports return type');
  }
} catch (e) {
  console.error('[DB] Migration 22 error (supplier_transactions return type):', e);
}

// ===== Migration 23: Add credit_limit and category to clients =====
try {
  const clientsCols = db.prepare("PRAGMA table_info(clients)").all();
  const clientsColNames = clientsCols.map(c => c.name);
  const clientMigrations = [];

  if (!clientsColNames.includes('credit_limit')) {
    clientMigrations.push("ALTER TABLE clients ADD COLUMN credit_limit REAL DEFAULT 0"); // 0 = no limit
  }
  if (!clientsColNames.includes('category')) {
    clientMigrations.push("ALTER TABLE clients ADD COLUMN category TEXT DEFAULT 'regular'"); // regular, vip, new
  }
  if (!clientsColNames.includes('last_visit')) {
    clientMigrations.push("ALTER TABLE clients ADD COLUMN last_visit TEXT");
  }
  if (!clientsColNames.includes('visit_count')) {
    clientMigrations.push("ALTER TABLE clients ADD COLUMN visit_count INTEGER DEFAULT 0");
  }

  if (clientMigrations.length > 0) {
    const migTrans = db.transaction(() => {
      for (const sql of clientMigrations) {
        db.prepare(sql).run();
      }
    });
    migTrans();
    console.log('[DB] ✅ Migration 23: Added', clientMigrations.length, 'columns to clients table');
  }
} catch (e) {
  console.error('[DB] Migration 23 error (clients credit_limit/category):', e);
}

// ===== Migration 24: Remove CHECK constraint from devices.type to allow any brand =====
try {
  // FORCED: Always check and fix the constraint
  console.log('[DB] Migration 24: === STARTING TYPE CONSTRAINT FIX ===');

  // Get current table schema
  const tableInfo = db.prepare(`SELECT sql FROM sqlite_master WHERE type='table' AND name='devices'`).get();
  const tableSql = tableInfo ? tableInfo.sql : '';

  console.log('[DB] Migration 24: Current devices table SQL:');
  console.log(tableSql);

  // Check if there's ANY type-related CHECK constraint in the schema
  const hasTypeInSchema = tableSql.includes("'iPhone'") || tableSql.includes("'Android'") || tableSql.includes("'Other'");

  // PRACTICAL TEST: Try to insert a custom brand
  let constraintBlocks = false;
  try {
    db.prepare(`INSERT INTO devices(type, model, purchase_cost) VALUES ('__NOKIA_TEST__', '__MIGRATION_TEST__', 0)`).run();
    db.prepare(`DELETE FROM devices WHERE model = '__MIGRATION_TEST__'`).run();
    console.log('[DB] Migration 24: Test insert PASSED - custom brands work');
  } catch (testErr) {
    console.log('[DB] Migration 24: Test insert FAILED:', testErr.message);
    if (testErr.message.includes('CHECK')) {
      constraintBlocks = true;
    }
  }

  console.log('[DB] Migration 24: Schema has type values:', hasTypeInSchema);
  console.log('[DB] Migration 24: Constraint blocks inserts:', constraintBlocks);

  // If constraint blocks OR schema shows the constraint, fix it
  if (constraintBlocks || hasTypeInSchema) {
    console.log('[DB] Migration 24: FIXING - Recreating devices table without type CHECK...');

    // SQLite doesn't support ALTER COLUMN, so we need to recreate the table
    db.exec(`
      -- Create new table without the CHECK constraint on type
      CREATE TABLE IF NOT EXISTS devices_new(
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        type TEXT NOT NULL,
        model TEXT NOT NULL,
        storage TEXT,
        condition TEXT CHECK(condition IN ('new','like_new','used','faulty')) NOT NULL DEFAULT 'used',
        color TEXT,
        imei1 TEXT,
        imei2 TEXT,
        purchase_cost REAL NOT NULL DEFAULT 0,
        expected_price REAL NOT NULL DEFAULT 0,
        status TEXT CHECK(status IN ('in_stock','sold','reserved','returned','scrapped','archived')) NOT NULL DEFAULT 'in_stock',
        battery_health INTEGER,
        has_box INTEGER NOT NULL DEFAULT 0,
        warehouse_id INTEGER,
        source TEXT,
        notes TEXT,
        ntra_tax REAL DEFAULT 0,
        purchase_date TEXT,
        quantity INTEGER DEFAULT 1,
        sale_price REAL DEFAULT 0,
        created_at TEXT NOT NULL DEFAULT (datetime('now', 'localtime')),
        updated_at TEXT
      );

      -- Copy data from old table
      INSERT INTO devices_new SELECT
        id, type, model, storage, condition, color, imei1, imei2,
        purchase_cost, expected_price, status, battery_health, has_box,
        warehouse_id, source, notes,
        COALESCE(ntra_tax, 0), purchase_date,
        COALESCE(quantity, 1), COALESCE(sale_price, 0),
        created_at, updated_at
      FROM devices;

      -- Drop old table
      DROP TABLE devices;

      -- Rename new table
      ALTER TABLE devices_new RENAME TO devices;

      -- Recreate indexes
      CREATE INDEX IF NOT EXISTS idx_devices_status ON devices(status);
      CREATE INDEX IF NOT EXISTS idx_devices_type ON devices(type);
      CREATE INDEX IF NOT EXISTS idx_devices_imei1 ON devices(imei1);
      CREATE INDEX IF NOT EXISTS idx_devices_warehouse ON devices(warehouse_id);
    `);

    console.log('[DB] ✅ Migration 24: devices.type CHECK constraint removed - any brand is now allowed');
    console.log('[DB] ✅ Migration 24: Nokia, Tecno, Honor, and any custom brand can now be added!');
  } else {
    console.log('[DB] ✅ Migration 24: devices.type already allows any brand (Nokia, Tecno, etc.)');
  }
} catch (e) {
  console.error('[DB] Migration 24 error (remove type CHECK):', e);
  console.error('[DB] Migration 24 error details:', e.message);
}

