// ===== Migration 26: Fix UTC timestamps to localtime =====
// التواريخ القديمة كانت تُخزن بتوقيت UTC، نحتاج تحويلها للتوقيت المحلي
try {
  // نتحقق إذا تم تطبيق هذه الـ migration من قبل
  const migrationFlag = db.prepare(`
    SELECT value FROM app_settings WHERE key = 'migration_26_utc_fix'
  `).get();

  if (!migrationFlag) {
    console.log('[DB] Migration 26: Fixing UTC timestamps to localtime...');

    // احسب فرق التوقيت المحلي بالساعات
    const now = new Date();
    const offsetMinutes = -now.getTimezoneOffset(); // offset بالدقائق (موجب = شرق UTC)
    const offsetHours = offsetMinutes / 60;

    // نحتاج نضيف الـ offset للتواريخ القديمة
    // مثلاً: مصر UTC+2، فنضيف ساعتين
    const offsetStr = offsetHours >= 0 ? `+${offsetHours} hours` : `${offsetHours} hours`;

    console.log(`[DB] Migration 26: Timezone offset is ${offsetHours} hours`);

    // تحديث التواريخ في الجداول الرئيسية
    const tablesToFix = [
      { table: 'sales', columns: ['created_at'] },
      { table: 'devices', columns: ['created_at', 'updated_at'] },
      { table: 'purchases', columns: ['created_at'] },
      { table: 'cash_ledger', columns: ['created_at'] },
      { table: 'safe_transactions', columns: ['created_at'] },
      { table: 'accessory_movements', columns: ['created_at'] },
      { table: 'clients', columns: ['created_at', 'last_visit'] },
      { table: 'suppliers', columns: ['created_at'] }
    ];

    const fixTrans = db.transaction(() => {
      for (const { table, columns } of tablesToFix) {
        for (const col of columns) {
          try {
            // تحديث فقط التواريخ اللي في اليوم الحالي (لتجنب مشاكل مع بيانات قديمة)
            db.prepare(`
              UPDATE ${table}
              SET ${col} = datetime(${col}, '${offsetStr}')
              WHERE date(${col}) = date('now')
                AND ${col} IS NOT NULL
                AND ${col} != ''
            `).run();
          } catch (tableErr) {
            // تجاهل الأخطاء للجداول غير الموجودة
          }
        }
      }

      // حفظ علامة أن الـ migration تمت
      db.prepare(`
        INSERT OR REPLACE INTO app_settings (key, value, updated_at)
        VALUES ('migration_26_utc_fix', '1', datetime('now', 'localtime'))
      `).run();
    });

    fixTrans();
    console.log('[DB] ✅ Migration 26: UTC timestamps fixed to localtime');
  } else {
    console.log('[DB] ✅ Migration 26: UTC fix already applied');
  }
} catch (e) {
  console.error('[DB] Migration 26 error (UTC fix):', e.message);
}

