// ===== Migration 32: Add wallet_id columns and migrate existing data =====
try {
  // Add wallet_id to cash_ledger
  const cashLedgerCols = db.prepare("PRAGMA table_info(cash_ledger)").all().map(c => c.name);
  if (!cashLedgerCols.includes('wallet_id')) {
    console.log('[DB] Migration 32: Adding wallet_id to cash_ledger...');
    db.prepare("ALTER TABLE cash_ledger ADD COLUMN wallet_id INTEGER").run();
    db.exec(`CREATE INDEX IF NOT EXISTS idx_cash_ledger_wallet_id ON cash_ledger(wallet_id)`);
    console.log('[DB] ✅ Migration 32: cash_ledger.wallet_id added');
  } else {
    console.log('[DB] ✅ Migration 32: cash_ledger.wallet_id already exists');
  }

  // Add wallet_id to repair_payments
  const repairPaymentsCols = db.prepare("PRAGMA table_info(repair_payments)").all().map(c => c.name);
  if (!repairPaymentsCols.includes('wallet_id')) {
    console.log('[DB] Migration 32: Adding wallet_id to repair_payments...');
    db.prepare("ALTER TABLE repair_payments ADD COLUMN wallet_id INTEGER").run();
    db.exec(`CREATE INDEX IF NOT EXISTS idx_repair_payments_wallet_id ON repair_payments(wallet_id)`);
    console.log('[DB] ✅ Migration 32: repair_payments.wallet_id added');
  } else {
    console.log('[DB] ✅ Migration 32: repair_payments.wallet_id already exists');
  }

  // Add wallet_id to safe_transactions
  const safeTransCols = db.prepare("PRAGMA table_info(safe_transactions)").all().map(c => c.name);
  if (!safeTransCols.includes('wallet_id')) {
    console.log('[DB] Migration 32: Adding wallet_id to safe_transactions...');
    db.prepare("ALTER TABLE safe_transactions ADD COLUMN wallet_id INTEGER").run();
    db.exec(`CREATE INDEX IF NOT EXISTS idx_safe_transactions_wallet_id ON safe_transactions(wallet_id)`);
    console.log('[DB] ✅ Migration 32: safe_transactions.wallet_id added');
  } else {
    console.log('[DB] ✅ Migration 32: safe_transactions.wallet_id already exists');
  }

  // ✅ Always create the 3 default wallets (cash, mobile_wallet, bank)
  const defaultWalletTypes = ['cash', 'mobile_wallet', 'bank'];
  const walletTypeNames = {
    'cash': 'كاش سائل - افتراضي',
    'mobile_wallet': 'محفظة إلكترونية - افتراضي',
    'bank': 'حساب بنكي - افتراضي'
  };

  for (const walletType of defaultWalletTypes) {
    // Check if default wallet for this type already exists
    const existingWallet = db.prepare(`
      SELECT id FROM payment_wallets
      WHERE type = ? AND is_default = 1
    `).get(walletType);

    if (!existingWallet) {
      console.log(`[DB] Migration 32: Creating default wallet for type: ${walletType}`);
      const walletName = walletTypeNames[walletType] || `${walletType} - افتراضي`;

      const result = db.prepare(`
        INSERT INTO payment_wallets (name, type, is_default, is_active)
        VALUES (?, ?, 1, 1)
      `).run(walletName, walletType);

      const walletId = result.lastInsertRowid;

      // Update cash_ledger records
      db.prepare(`
        UPDATE cash_ledger
        SET wallet_id = ?
        WHERE wallet_type = ? AND wallet_id IS NULL
      `).run(walletId, walletType);

      // Update repair_payments records
      db.prepare(`
        UPDATE repair_payments
        SET wallet_id = ?
        WHERE wallet_type = ? AND wallet_id IS NULL
      `).run(walletId, walletType);

      // Update safe_transactions records
      db.prepare(`
        UPDATE safe_transactions
        SET wallet_id = ?
        WHERE wallet_type = ? AND wallet_id IS NULL
      `).run(walletId, walletType);

      console.log(`[DB] ✅ Migration 32: Created and linked default wallet for ${walletType}`);
    }
  }

  console.log('[DB] ✅ Migration 32: Data migration completed');
} catch (e) {
  console.error('[DB] Migration 32 error (wallet_id migration):', e.message);
}

