// ===== Migration 38: Add part_id column to purchase_invoice_items and make accessory_id nullable =====
try {
  const purchaseInvoiceItemsCols = db.prepare("PRAGMA table_info(purchase_invoice_items)").all().map(col => col.name);
  if (!purchaseInvoiceItemsCols.includes('part_id')) {
    console.log('[DB] Migration 38: Adding part_id column to purchase_invoice_items...');
    db.prepare("ALTER TABLE purchase_invoice_items ADD COLUMN part_id INTEGER NULL").run();
    console.log('[DB] ✅ Migration 38: purchase_invoice_items.part_id added');
  } else {
    console.log('[DB] ✅ Migration 38: purchase_invoice_items.part_id already exists');
  }
  
  // ✅ Migration 38.1: إزالة NOT NULL constraint من accessory_id
  // SQLite لا يدعم ALTER COLUMN مباشرة، لذلك نحتاج إلى إعادة إنشاء الجدول
  const tableInfo = db.prepare("PRAGMA table_info(purchase_invoice_items)").all();
  const accessoryIdCol = tableInfo.find(col => col.name === 'accessory_id');
  
  if (accessoryIdCol && accessoryIdCol.notnull === 1) {
    console.log('[DB] Migration 38.1: Making accessory_id nullable in purchase_invoice_items...');
    
    // حفظ البيانات الموجودة
    const existingData = db.prepare("SELECT * FROM purchase_invoice_items").all();
    
    // إعادة إنشاء الجدول بدون NOT NULL constraint على accessory_id
    db.exec(`
      CREATE TABLE IF NOT EXISTS purchase_invoice_items_new (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        invoice_id INTEGER NOT NULL,
        accessory_id INTEGER NULL,
        part_id INTEGER NULL,
        quantity INTEGER NOT NULL,
        unit_price REAL NOT NULL,
        total_price REAL NOT NULL,
        notes TEXT,
        created_at TEXT DEFAULT (datetime('now', 'localtime')),
        FOREIGN KEY (invoice_id) REFERENCES purchase_invoices(id) ON DELETE CASCADE,
        FOREIGN KEY (accessory_id) REFERENCES accessories(id) ON DELETE CASCADE,
        FOREIGN KEY (part_id) REFERENCES repair_parts(id) ON DELETE CASCADE
      )
    `);
    
    // نسخ البيانات
    if (existingData.length > 0) {
      const insertStmt = db.prepare(`
        INSERT INTO purchase_invoice_items_new 
        (id, invoice_id, accessory_id, part_id, quantity, unit_price, total_price, notes, created_at)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
      `);
      
      existingData.forEach(row => {
        insertStmt.run(
          row.id,
          row.invoice_id,
          row.accessory_id,
          row.part_id || null,
          row.quantity,
          row.unit_price,
          row.total_price,
          row.notes,
          row.created_at
        );
      });
    }
    
    // حذف الجدول القديم وإنشاء الجديد
    db.exec("DROP TABLE purchase_invoice_items");
    db.exec("ALTER TABLE purchase_invoice_items_new RENAME TO purchase_invoice_items");
    
    console.log('[DB] ✅ Migration 38.1: accessory_id is now nullable');
  } else {
    console.log('[DB] ✅ Migration 38.1: accessory_id is already nullable');
  }
} catch (e) {
  console.error('[DB] Migration 38 error (purchase_invoice_items):', e.message);
}

