// ===== Migration 45: Add target_wallet_id for proper wallet-to-wallet transfer tracking =====
try {
  const safeTxCols = db.prepare("PRAGMA table_info(safe_transactions)").all().map(c => c.name);
  console.log('[DB] Migration 45: safe_transactions columns:', safeTxCols.join(', '));

  if (!safeTxCols.includes('target_wallet_id')) {
    console.log('[DB] Migration 45: Adding target_wallet_id column to safe_transactions...');
    db.prepare("ALTER TABLE safe_transactions ADD COLUMN target_wallet_id INTEGER REFERENCES payment_wallets(id)").run();
    console.log('[DB] ✅ Migration 45: safe_transactions.target_wallet_id added');

    // ✅ تحديث التحويلات الموجودة: ربط target_wallet بـ target_wallet_id
    console.log('[DB] Migration 45: Updating existing transfers with target_wallet_id...');
    const transfers = db.prepare(`
      SELECT st.id, st.target_wallet, pw.id as wallet_id
      FROM safe_transactions st
      LEFT JOIN payment_wallets pw ON pw.type = st.target_wallet AND pw.is_default = 1
      WHERE st.type = 'transfer' AND st.target_wallet IS NOT NULL AND st.target_wallet_id IS NULL
    `).all();

    for (const t of transfers) {
      if (t.wallet_id) {
        db.prepare(`UPDATE safe_transactions SET target_wallet_id = ? WHERE id = ?`).run(t.wallet_id, t.id);
      }
    }
    console.log(`[DB] ✅ Migration 45: Updated ${transfers.length} existing transfers with target_wallet_id`);
  } else {
    console.log('[DB] ✅ Migration 45: safe_transactions.target_wallet_id already exists');
  }
} catch (e) {
  console.error('[DB] Migration 45 error (target_wallet_id):', e.message);
}

