// ===== Migration 53: Multi-User Cash Drawer System =====
// ═════════════════════════════════════════════════════════════════════
// إضافة user_id لـ cash_ledger و shift_closings
// كل كاشير له درج كاش خاص به - التقفيل يكون per-user
// ═════════════════════════════════════════════════════════════════════
try {
  console.log('[DB] Migration 53: Adding multi-user cash drawer support...');

  // 1. إضافة user_id لجدول cash_ledger
  const cashLedgerCols53 = db.prepare("PRAGMA table_info(cash_ledger)").all().map(c => c.name);
  if (!cashLedgerCols53.includes('user_id')) {
    console.log('[DB] Migration 53: Adding user_id column to cash_ledger...');
    db.prepare("ALTER TABLE cash_ledger ADD COLUMN user_id INTEGER").run();
    db.exec(`CREATE INDEX IF NOT EXISTS idx_cash_ledger_user_id ON cash_ledger(user_id)`);
    console.log('[DB] ✅ Migration 53: cash_ledger.user_id added');
  } else {
    console.log('[DB] ✅ Migration 53: cash_ledger.user_id already exists');
  }

  // 2. إضافة username لجدول cash_ledger (للعرض السريع)
  if (!cashLedgerCols53.includes('username')) {
    console.log('[DB] Migration 53: Adding username column to cash_ledger...');
    db.prepare("ALTER TABLE cash_ledger ADD COLUMN username TEXT").run();
    console.log('[DB] ✅ Migration 53: cash_ledger.username added');
  } else {
    console.log('[DB] ✅ Migration 53: cash_ledger.username already exists');
  }

  // 3. إضافة user_id لجدول shift_closings
  const shiftClosingsCols = db.prepare("PRAGMA table_info(shift_closings)").all().map(c => c.name);
  if (!shiftClosingsCols.includes('user_id')) {
    console.log('[DB] Migration 53: Adding user_id column to shift_closings...');
    db.prepare("ALTER TABLE shift_closings ADD COLUMN user_id INTEGER").run();
    db.exec(`CREATE INDEX IF NOT EXISTS idx_shift_closings_user_id ON shift_closings(user_id)`);
    console.log('[DB] ✅ Migration 53: shift_closings.user_id added');
  } else {
    console.log('[DB] ✅ Migration 53: shift_closings.user_id already exists');
  }

  // 4. إضافة حقل is_open لتتبع حالة الشفت (مفتوح/مغلق)
  if (!shiftClosingsCols.includes('is_open')) {
    console.log('[DB] Migration 53: Adding is_open column to shift_closings...');
    db.prepare("ALTER TABLE shift_closings ADD COLUMN is_open INTEGER DEFAULT 0").run();
    console.log('[DB] ✅ Migration 53: shift_closings.is_open added');
  } else {
    console.log('[DB] ✅ Migration 53: shift_closings.is_open already exists');
  }

  // 5. إضافة shift_id لجدول cash_ledger (ربط الحركة بالشفت)
  if (!cashLedgerCols53.includes('shift_id')) {
    console.log('[DB] Migration 53: Adding shift_id column to cash_ledger...');
    db.prepare("ALTER TABLE cash_ledger ADD COLUMN shift_id INTEGER").run();
    db.exec(`CREATE INDEX IF NOT EXISTS idx_cash_ledger_shift_id ON cash_ledger(shift_id)`);
    console.log('[DB] ✅ Migration 53: cash_ledger.shift_id added');
  } else {
    console.log('[DB] ✅ Migration 53: cash_ledger.shift_id already exists');
  }

  // 6. إنشاء جدول user_shifts لتتبع شفتات المستخدمين النشطة
  const userShiftsExists = db.prepare("SELECT name FROM sqlite_master WHERE type='table' AND name='user_shifts'").get();
  if (!userShiftsExists) {
    console.log('[DB] Migration 53: Creating user_shifts table...');
    db.exec(`
      CREATE TABLE IF NOT EXISTS user_shifts (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        user_id INTEGER NOT NULL,
        username TEXT NOT NULL,
        opened_at TEXT NOT NULL DEFAULT (datetime('now', 'localtime')),
        closed_at TEXT,
        opening_balance REAL NOT NULL DEFAULT 0,
        closing_balance REAL,
        status TEXT CHECK(status IN ('open', 'closed')) DEFAULT 'open',
        shift_closing_id INTEGER,
        notes TEXT,
        UNIQUE(user_id, status) -- مستخدم واحد = شفت مفتوح واحد فقط
      )
    `);
    db.exec(`CREATE INDEX IF NOT EXISTS idx_user_shifts_user_id ON user_shifts(user_id)`);
    db.exec(`CREATE INDEX IF NOT EXISTS idx_user_shifts_status ON user_shifts(status)`);
    console.log('[DB] ✅ Migration 53: user_shifts table created');
  } else {
    console.log('[DB] ✅ Migration 53: user_shifts table already exists');
  }

  console.log('[DB] ✅ Migration 53: Multi-user cash drawer system completed');
} catch (e) {
  console.error('[DB] Migration 53 error (multi-user cash drawer):', e.message);
}

