// ===== Migration 57: Add 'refunded' to repair_tickets status CHECK constraint =====
try {
  // SQLite مش بيسمح بتعديل CHECK constraint مباشرة
  // الحل: نعمل recreate للـ table مع الـ constraint الجديدة
  const tableInfo = db.prepare("SELECT sql FROM sqlite_master WHERE type='table' AND name='repair_tickets'").get();
  if (tableInfo && tableInfo.sql && !tableInfo.sql.includes("'refunded'")) {
    console.log('[DB] Migration 57: Adding refunded status to repair_tickets...');

    // 1. إنشاء table مؤقت بنفس البيانات
    db.exec(`CREATE TABLE IF NOT EXISTS repair_tickets_backup AS SELECT * FROM repair_tickets`);

    // 2. حذف الـ table الأصلي
    db.exec(`DROP TABLE repair_tickets`);

    // 3. إعادة إنشاء الـ table مع الـ constraint الجديدة
    const newSql = tableInfo.sql.replace(
      "('received','diagnosing','waiting_approval','in_repair','ready','delivered','cancelled')",
      "('received','diagnosing','waiting_approval','in_repair','ready','delivered','cancelled','refunded')"
    );
    db.exec(newSql);

    // 4. نقل البيانات من الـ backup
    const backupCols = db.prepare("PRAGMA table_info(repair_tickets_backup)").all().map(c => c.name);
    const targetCols = db.prepare("PRAGMA table_info(repair_tickets)").all().map(c => c.name);
    const commonCols = backupCols.filter(c => targetCols.includes(c)).join(', ');
    db.exec(`INSERT INTO repair_tickets (${commonCols}) SELECT ${commonCols} FROM repair_tickets_backup`);

    // 5. حذف الـ backup
    db.exec(`DROP TABLE repair_tickets_backup`);

    // 6. إعادة إنشاء الـ indexes
    db.exec(`CREATE INDEX IF NOT EXISTS idx_repair_tickets_status ON repair_tickets(status)`);
    db.exec(`CREATE INDEX IF NOT EXISTS idx_repair_tickets_customer ON repair_tickets(customer_phone)`);
    db.exec(`CREATE UNIQUE INDEX IF NOT EXISTS idx_repair_tickets_barcode ON repair_tickets(barcode) WHERE barcode IS NOT NULL`);

    console.log('[DB] ✅ Migration 57: refunded status added to repair_tickets');
  } else {
    console.log('[DB] ✅ Migration 57: refunded status already exists in repair_tickets');
  }
} catch (e) {
  console.error('[DB] Migration 57 error (refunded status):', e.message);
}

