// POST /accessories - إضافة إكسسوار جديد
if (route === 'accessories' && req.method === 'POST') {
  const authCheck = requireAuth(req, route);
  if (!authCheck.authorized) return err(authCheck.error, authCheck.code);

  const permCheck = requirePermission(authCheck.session, route, req.method);
  if (!permCheck.authorized) return err(permCheck.error, permCheck.code);

  try {
    const p = await body(req);
    const name = reqStr(p.name, 'اسم الإكسسوار مطلوب');

    // ═══ V6.1: دعم الباركود اليدوي أو التلقائي ═══
    let short_code = (p.short_code || '').trim();
    let barcode = (p.barcode || '').trim();

    // إذا تم تقديم باركود يدوي، تحقق من عدم تكراره
    if (short_code || barcode) {
      const barcodeToCheck = short_code || barcode;
      const existingBarcode = db.prepare(`
        SELECT id FROM accessories WHERE short_code = ? OR barcode = ?
      `).get(barcodeToCheck, barcodeToCheck);
      if (existingBarcode) {
        return err(`الباركود ${barcodeToCheck} موجود مسبقاً`, 400);
      }
    }

    // توليد short_code تلقائي إذا لم يتم تقديمه
    // النظام الموحد: إكسسوارات 500000-899999 (6 أرقام)
    if (!short_code) {
      const lastCode = db.prepare(`
        SELECT MAX(CAST(short_code AS INTEGER)) as lastCode
        FROM accessories
        WHERE short_code IS NOT NULL AND short_code != ''
        AND short_code NOT LIKE 'AC%'
        AND CAST(short_code AS INTEGER) >= 500000
        AND CAST(short_code AS INTEGER) < 900000
      `).get();

      let nextShortCode = (lastCode?.lastCode || 499999) + 1;
      if (nextShortCode < 500000) nextShortCode = 500000;
      if (nextShortCode >= 900000) {
        console.warn('[DB] ⚠️ Accessory short_code range exhausted!');
        nextShortCode = 899999; // حد أقصى
      }
      short_code = String(nextShortCode);
    }

    // استخدام short_code كـ barcode إذا لم يتم تقديم barcode
    if (!barcode) barcode = short_code;

    const result = db.prepare(`
      INSERT INTO accessories (
        warehouse_id, name, code, condition, category, brand, model, compatible_models,
        barcode, sku, purchase_price, sale_price, sell_price, wholesale_price,
        quantity, min_stock, max_stock, reorder_point,
        supplier_id, location, image_url, color, size, weight,
        notes, status, short_code
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    `).run(
      p.warehouse_id || null,
      name,
      p.code || '',
      p.condition || 'جديد',
      p.category || '',
      p.brand || '',
      p.model || '',
      p.compatible_models || '',
      barcode, // استخدام المتغير المحسوب
      p.sku || null,
      num(p.purchase_price, 0),
      num(p.sale_price, 0),
      num(p.sell_price, 0),
      num(p.wholesale_price, 0),
      num(p.quantity, 0),
      num(p.min_stock, 5),
      num(p.max_stock, 100),
      num(p.reorder_point, 10),
      p.supplier_id || null,
      p.location || '',
      p.image_url || '',
      p.color || '',
      p.size || '',
      p.weight || '',
      p.notes || '',
      p.status || 'متاح',
      short_code
    );

    const accessoryId = result.lastInsertRowid;

    // تسجيل الحركة الافتتاحية إذا كانت الكمية أكبر من صفر
    if (num(p.quantity, 0) > 0) {
      db.prepare(`
        INSERT INTO accessory_movements (
          accessory_id, type, quantity, quantity_before, quantity_after,
          unit_price, total_price, reference_type, notes, user_id
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
      `).run(
        accessoryId,
        'adjustment',
        num(p.quantity, 0),
        0,
        num(p.quantity, 0),
        num(p.purchase_price, 0),
        num(p.quantity, 0) * num(p.purchase_price, 0),
        'manual',
        'كمية افتتاحية',
        authCheck.session.userId
      );
    }

    logAudit('ACCESSORY_CREATED', {
      id: accessoryId,
      name,
      quantity: num(p.quantity, 0),
      short_code
    }, authCheck.session.userId);

    markTableModified('accessories'); // 🔄 Sync
    return json({
      success: true,
      id: accessoryId,
      short_code,
      message: `تم إضافة "${name}" بنجاح`
    });
  } catch (error) {
    console.error('[DB] Error creating accessory:', error);
    return err(error.message, 500);
  }
}

// ═════════════════════════════════════
// 📦 ACCESSORIES - BULK IMPORT (استيراد جماعي)
// ═════════════════════════════════════
if (route === 'accessories-bulk-import' && req.method === 'POST') {
  const bulkSession = getSessionFromRequest(req);
  const p = await body(req);
  const items = p.items || [];
  const warehouseId = p.warehouse_id ? parseInt(p.warehouse_id) : null;

  if (!items.length) return err('يجب إضافة صنف واحد على الأقل', 400);

  // تجميع الباركودات الموجودة مرة واحدة
  const existingCodes = db.prepare(
    "SELECT short_code FROM accessories WHERE short_code IS NOT NULL AND short_code != ''"
  ).all().map(r => r.short_code);
  const usedSet = new Set(existingCodes);

  // تجهيز أول باركود متاح (نطاق 500000-899999)
  const lastCode = db.prepare(`
    SELECT MAX(CAST(short_code AS INTEGER)) as lastCode
    FROM accessories
    WHERE short_code IS NOT NULL AND short_code != ''
    AND short_code NOT LIKE 'AC%'
    AND CAST(short_code AS INTEGER) >= 500000
    AND CAST(short_code AS INTEGER) < 900000
  `).get();
  let nextCode = (lastCode?.lastCode || 499999) + 1;
  if (nextCode < 500000) nextCode = 500000;

  const results = [];
  const errors = [];

  const insertAcc = db.prepare(`
    INSERT INTO accessories (
      warehouse_id, name, code, condition, category, brand,
      barcode, sku, purchase_price, sale_price, sell_price,
      quantity, min_stock, notes, status, short_code
    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
  `);
  const insertMovement = db.prepare(`
    INSERT INTO accessory_movements (
      accessory_id, type, quantity, quantity_before, quantity_after,
      unit_price, total_price, reference_type, notes, user_id
    ) VALUES (?, ?, ?, 0, ?, ?, ?, ?, ?, ?)
  `);

  const transaction = db.transaction(() => {
    for (let i = 0; i < items.length; i++) {
      const item = items[i];
      try {
        const name = (item.name || '').trim();
        if (!name) {
          errors.push({ index: i, error: 'اسم الإكسسوار مطلوب' });
          continue;
        }

        const category = item.category ? sanitizeText(item.category, 100) : '';
        const brand = item.brand ? sanitizeText(item.brand, 100) : '';
        const sku = item.sku ? sanitizeText(item.sku, 50) : null;
        const code = item.code ? sanitizeText(item.code, 50) : '';
        const condition = item.condition || 'جديد';
        const purchasePrice = num(item.purchase_price, 0);
        const salePrice = num(item.sale_price || item.sell_price, 0);
        const quantity = num(item.quantity, 0);
        const minStock = num(item.min_stock, 5);
        const notes = item.notes ? sanitizeNotes(item.notes) : '';
        const manualBarcode = (item.barcode || item.short_code || '').trim();

        // تحديد الباركود
        let short_code;
        if (manualBarcode) {
          if (usedSet.has(manualBarcode)) {
            errors.push({ index: i, name, error: `الباركود ${manualBarcode} موجود مسبقاً` });
            continue;
          }
          short_code = manualBarcode;
        } else {
          if (nextCode >= 900000) {
            short_code = String(500000 + Math.floor(Math.random() * 400000));
          } else {
            short_code = String(nextCode);
            nextCode++;
            while (usedSet.has(String(nextCode)) && nextCode < 900000) {
              nextCode++;
            }
          }
        }

        usedSet.add(short_code);
        const barcode = short_code;

        const info = insertAcc.run(
          warehouseId, name, code, condition, category, brand,
          barcode, sku, purchasePrice, salePrice, salePrice,
          quantity, minStock, notes, 'متاح', short_code
        );
        const accId = info.lastInsertRowid;

        if (quantity > 0) {
          insertMovement.run(
            accId, 'import', quantity, quantity,
            purchasePrice, quantity * purchasePrice,
            'import', 'استيراد من Excel', bulkSession?.userId || null
          );
        }

        results.push({ id: accId, name, short_code });
      } catch (e) {
        errors.push({ index: i, name: item.name || '', error: e.message });
      }
    }
  });

  transaction();

  markTableModified('accessories');
  logAudit('ACCESSORIES_BULK_IMPORTED', {
    total: items.length,
    added: results.length,
    failed: errors.length,
    warehouse_id: warehouseId
  }, bulkSession?.userId || null);

  return json({
    success: true,
    added: results.length,
    failed: errors.length,
    errors: errors.length > 0 ? errors : undefined
  });
}

// ═════════════════════════════════════
// 📊 ACCESSORIES - AVERAGE PRICES (توحيد الأسعار)
// ═════════════════════════════════════
if (route === 'accessories/average-prices' && req.method === 'POST') {
  const authCheck = requireAuth(req, route);
  if (!authCheck.authorized) return err(authCheck.error, authCheck.code);

  try {
    const p = await body(req);

    const itemIds = p.item_ids;
    if (!Array.isArray(itemIds) || itemIds.length < 2) {
      return json({ success: false, error: 'يجب تحديد صنفين على الأقل' }, 400);
    }

    const avgPurchase = p.avg_purchase_price !== null ? Number(p.avg_purchase_price) : null;
    const avgSale = p.avg_sale_price !== null ? Number(p.avg_sale_price) : null;

    if (avgPurchase === null && avgSale === null) {
      return json({ success: false, error: 'يجب تحديد قيمة واحدة على الأقل للتوحيد' }, 400);
    }

    // بناء الاستعلام
    const updates = [];
    const values = [];

    if (avgPurchase !== null) {
      updates.push('purchase_price = ?');
      values.push(avgPurchase);
    }

    if (avgSale !== null) {
      updates.push('sale_price = ?');
      updates.push('sell_price = ?');
      values.push(avgSale);
      values.push(avgSale);
    }

    updates.push("updated_at = datetime('now', 'localtime')");

    // تنفيذ التحديث
    const placeholders = itemIds.map(() => '?').join(',');
    const updateStmt = db.prepare(`UPDATE accessories SET ${updates.join(', ')} WHERE id IN (${placeholders}) AND is_active = 1`);
    const result = updateStmt.run(...values, ...itemIds);

    logAudit('ACCESSORIES_PRICES_AVERAGED', {
      item_ids: itemIds,
      avg_purchase_price: avgPurchase,
      avg_sale_price: avgSale,
      updated: result.changes
    }, authCheck.session.userId);

    console.log(`[DB] ✅ Average prices applied to ${result.changes} accessories`);

    return json({
      success: true,
      updated: result.changes,
      avg_purchase_price: avgPurchase,
      avg_sale_price: avgSale
    });
  } catch (error) {
    console.error('[DB] Error averaging accessory prices:', error);
    return err(error.message, 500);
  }
}

// PUT /accessories/:id - تعديل إكسسوار (تحديث جزئي: فقط الحقول المرسلة تُحدَّث، لتفادي مسح سعر البيع عند التوريد)
if (route.startsWith('accessories/') && req.method === 'PUT') {
  const authCheck = requireAuth(req, route);
  if (!authCheck.authorized) return err(authCheck.error, authCheck.code);

  const permCheck = requirePermission(authCheck.session, route, req.method);
  if (!permCheck.authorized) return err(permCheck.error, permCheck.code);

  try {
    const id = posInt(route.split('/')[1], 'رقم الإكسسوار غير صحيح');
    const p = await body(req);

    const row = db.prepare('SELECT id FROM accessories WHERE id = ? AND is_active = 1').get(id);
    if (!row) return err('الإكسسوار غير موجود', 404);

    const allowed = {
      name: (v) => (v != null && v !== '') ? sanitizeText(String(v), 500) : null,
      category: (v) => (v != null && v !== '') ? sanitizeText(String(v), 200) : null,
      brand: (v) => (v != null && v !== '') ? sanitizeText(String(v), 200) : null,
      model: (v) => (v != null && v !== '') ? sanitizeText(String(v), 200) : null,
      compatible_models: (v) => (v != null && v !== '') ? sanitizeText(String(v), 500) : null,
      barcode: (v) => (v != null && v !== '') ? sanitizeText(String(v), 100) : null,
      short_code: (v) => (v != null && v !== '') ? sanitizeText(String(v), 50) : null,
      sku: (v) => (v != null && v !== '') ? sanitizeText(String(v), 100) : null,
      purchase_price: (v) => num(v, 0),
      sell_price: (v) => num(v, 0),
      sale_price: (v) => num(v, 0),
      wholesale_price: (v) => num(v, 0),
      quantity: (v) => num(v, 0),
      min_stock: (v) => num(v, 5),
      max_stock: (v) => num(v, 100),
      reorder_point: (v) => num(v, 10),
      supplier_id: (v) => { if (v == null || v === '') return null; const n = parseInt(v, 10); return Number.isFinite(n) ? n : null; },
      location: (v) => (v != null && v !== '') ? sanitizeText(String(v), 200) : null,
      image_url: (v) => (v != null && v !== '') ? String(v) : null,
      color: (v) => (v != null && v !== '') ? sanitizeText(String(v), 100) : null,
      size: (v) => (v != null && v !== '') ? sanitizeText(String(v), 100) : null,
      weight: (v) => (v != null && v !== '') ? sanitizeText(String(v), 100) : null,
      notes: (v) => (v != null && v !== '') ? sanitizeNotes(String(v)) : null,
      status: (v) => (v != null && v !== '') ? sanitizeText(String(v), 50) : null,
      condition: (v) => (v != null && v !== '') ? sanitizeText(String(v), 50) : null,
      warehouse_id: (v) => { if (v == null || v === '') return null; const n = parseInt(v, 10); return Number.isFinite(n) ? n : null; }
    };

    const updates = [];
    const values = [];
    if (p.sell_price !== undefined || p.sale_price !== undefined) {
      const sellPriceValue = num(p.sell_price ?? p.sale_price, 0);
      updates.push('sell_price = ?', 'sale_price = ?');
      values.push(sellPriceValue, sellPriceValue);
    }
    for (const [key, fn] of Object.entries(allowed)) {
      if (key === 'sell_price' || key === 'sale_price') continue;
      if (p[key] === undefined) continue;
      updates.push(`${key} = ?`);
      values.push(fn(p[key]));
    }
    if (updates.length > 0) {
      updates.push("updated_at = datetime('now', 'localtime')");
      values.push(id);
      db.prepare(`UPDATE accessories SET ${updates.join(', ')} WHERE id = ? AND is_active = 1`).run(...values);
    }

    logAudit('ACCESSORY_UPDATED', { id, changes: p }, authCheck.session.userId);

    return json({ success: true, message: 'تم تحديث الإكسسوار بنجاح' });
  } catch (error) {
    console.error('[DB] Error updating accessory:', error);
    return err(error.message, 500);
  }
}

// POST /accessories/:id/add-quantity - إضافة كمية للإكسسوار
if (route.match(/^accessories\/\d+\/add-quantity$/) && req.method === 'POST') {
  const authCheck = requireAuth(req, route);
  if (!authCheck.authorized) return err(authCheck.error, authCheck.code);

  const permCheck = requirePermission(authCheck.session, 'accessories', 'write');
  if (!permCheck.authorized) return err(permCheck.error, permCheck.code);

  try {
    const id = posInt(route.split('/')[1], 'رقم الإكسسوار غير صحيح');
    const p = await body(req);
    const quantity = posInt(p.quantity, 'الكمية مطلوبة');
    const purchasePrice = num(p.purchase_price, 0);
    const notes = p.notes || '';

    // Get current accessory
    const accessory = db.prepare('SELECT * FROM accessories WHERE id = ? AND is_active = 1').get(id);
    if (!accessory) {
      return err('الإكسسوار غير موجود', 404);
    }

    // Calculate quantities
    const quantityBefore = accessory.quantity;
    const quantityAfter = accessory.quantity + quantity;

    // Update quantity
    db.prepare(`
      UPDATE accessories SET
        quantity = quantity + ?,
        purchase_price = CASE WHEN ? > 0 THEN ? ELSE purchase_price END,
        updated_at = datetime('now', 'localtime')
      WHERE id = ?
    `).run(quantity, purchasePrice, purchasePrice, id);

    // Record movement
    db.prepare(`
      INSERT INTO accessory_movements (accessory_id, type, quantity, quantity_before, quantity_after, unit_price, total_price, notes, user_id, created_at)
      VALUES (?, 'in', ?, ?, ?, ?, ?, ?, ?, datetime('now', 'localtime'))
    `).run(id, quantity, quantityBefore, quantityAfter, purchasePrice, purchasePrice * quantity, notes, authCheck.session.userId);

    logAudit('ACCESSORY_QUANTITY_ADDED', { id, quantity, purchasePrice, notes }, authCheck.session.userId);

    return json({
      success: true,
      message: `تمت إضافة ${quantity} وحدة بنجاح`,
      newQuantity: accessory.quantity + quantity
    });
  } catch (error) {
    console.error('[DB] Error adding accessory quantity:', error);
    return err(error.message, 500);
  }
}

