// POST /warehouse-items - إضافة صنف لمخزن مخصص
// PUT /warehouse-items/:id - تعديل صنف
// DELETE /warehouse-items/:id - حذف صنف
// (نفس المنطق السابق مع تعديل الجداول)

// ───────────────────────────────────────────────────────────────────
// 📄 PURCHASE INVOICES (فواتير التوريد)
// ───────────────────────────────────────────────────────────────────

// GET /purchase-invoices - جلب كل فواتير التوريد
// يدعم parameter: type=accessories (للإكسسوارات فقط) أو type=repair_parts (لقطع الصيانة فقط)
if (route === 'purchase-invoices' && req.method === 'GET') {
  const authCheck = requireAuth(req, route);
  if (!authCheck.authorized) return err(authCheck.error, authCheck.code);

  const permCheck = requirePermission(authCheck.session, 'accessories', 'read');
  if (!permCheck.authorized) return err(permCheck.error, permCheck.code);

  try {
    const url = new URL(req.url, `http://${req.headers.get('host') || 'localhost'}`);
    const from = url.searchParams.get('from');
    const to = url.searchParams.get('to');
    const supplierId = url.searchParams.get('supplier_id');
    const invoiceType = url.searchParams.get('type'); // 'accessories' أو 'repair_parts'

    let sql = `
      SELECT
        pi.*,
        s.name as supplier_name,
        u.username as created_by,
        (SELECT COUNT(*) FROM purchase_invoice_items WHERE invoice_id = pi.id) as items_count
      FROM purchase_invoices pi
      LEFT JOIN suppliers s ON pi.supplier_id = s.id
      LEFT JOIN users u ON pi.user_id = u.id
      WHERE 1=1
    `;

    const params = [];

    // ═══════════════════════════════════════════════════════════════
    // 🔍 فلترة حسب نوع الفاتورة (إكسسوارات أو قطع صيانة)
    // ═══════════════════════════════════════════════════════════════
    if (invoiceType === 'accessories') {
      // فواتير الإكسسوارات فقط (التي تحتوي على accessory_id ولا تحتوي على part_id)
      sql += ` AND EXISTS (
        SELECT 1 FROM purchase_invoice_items pii
        WHERE pii.invoice_id = pi.id AND pii.accessory_id IS NOT NULL
      )
      AND NOT EXISTS (
        SELECT 1 FROM purchase_invoice_items pii
        WHERE pii.invoice_id = pi.id AND pii.part_id IS NOT NULL
      )`;
    } else if (invoiceType === 'repair_parts') {
      // فواتير قطع الصيانة فقط (التي تحتوي على part_id)
      sql += ` AND EXISTS (
        SELECT 1 FROM purchase_invoice_items pii
        WHERE pii.invoice_id = pi.id AND pii.part_id IS NOT NULL
      )`;
    }

    if (from) {
      sql += ` AND date(pi.invoice_date) >= ?`;
      params.push(from);
    }

    if (to) {
      sql += ` AND date(pi.invoice_date) <= ?`;
      params.push(to);
    }

    if (supplierId) {
      sql += ` AND pi.supplier_id = ?`;
      params.push(supplierId);
    }

    sql += ` ORDER BY pi.created_at DESC`;

    const invoices = db.prepare(sql).all(...params);

    return json(invoices);

  } catch (error) {
    console.error('[PURCHASE-INVOICES] Error fetching:', error);
    return err('فشل جلب فواتير التوريد: ' + error.message, 500);
  }
}

// GET /purchase-invoices/:id - جلب فاتورة محددة مع أصنافها
if (route.match(/^purchase-invoices\/\d+$/) && req.method === 'GET') {
  const authCheck = requireAuth(req, route);
  if (!authCheck.authorized) return err(authCheck.error, authCheck.code);

  const permCheck = requirePermission(authCheck.session, 'accessories', 'read');
  if (!permCheck.authorized) return err(permCheck.error, permCheck.code);

  try {
    const id = posInt(route.split('/')[1], 'رقم الفاتورة غير صحيح');

    const invoice = db.prepare(`
      SELECT 
        pi.*,
        s.name as supplier_name,
        u.username as created_by
      FROM purchase_invoices pi
      LEFT JOIN suppliers s ON pi.supplier_id = s.id
      LEFT JOIN users u ON pi.user_id = u.id
      WHERE pi.id = ?
    `).get(id);

    if (!invoice) {
      return err('الفاتورة غير موجودة', 404);
    }

    const items = db.prepare(`
      SELECT 
        pii.*,
        a.name as accessory_name,
        a.category,
        a.brand,
        a.barcode
      FROM purchase_invoice_items pii
      LEFT JOIN accessories a ON pii.accessory_id = a.id
      WHERE pii.invoice_id = ?
      ORDER BY pii.id
    `).all(id);

    return json({ invoice, items });
    
  } catch (error) {
    console.error('[PURCHASE-INVOICES] Error fetching invoice:', error);
    return err('فشل جلب الفاتورة: ' + error.message, 500);
  }
}

// POST /purchase-invoices - إنشاء فاتورة توريد جديدة
if (route === 'purchase-invoices' && req.method === 'POST') {
  const authCheck = requireAuth(req, route);
  if (!authCheck.authorized) return err(authCheck.error, authCheck.code);

  const permCheck = requirePermission(authCheck.session, 'accessories', 'write');
  if (!permCheck.authorized) return err(permCheck.error, permCheck.code);

  try {
    const p = await body(req);
    
    if (!p.items || !Array.isArray(p.items) || p.items.length === 0) {
      return err('يجب إضافة صنف واحد على الأقل', 400);
    }

    // ✅ التحقق من الأصناف - دعم accessory_id و part_id
    for (const item of p.items) {
      if ((!item.accessory_id && !item.part_id) || item.quantity <= 0) {
        return err('بيانات الأصناف غير صحيحة', 400);
      }
    }

    let totalAmount = 0;
    p.items.forEach(item => {
      totalAmount += (item.quantity * item.unit_price) || 0;
    });

    // توليد رقم فاتورة موحد للمشتريات
    let invoiceNumber = p.invoice_number;
    if (!invoiceNumber) {
      try {
        const counter = db.prepare(`SELECT * FROM invoice_counters WHERE type = 'purchase'`).get();
        if (counter) {
          const newNumber = counter.last_number + 1;
          db.prepare(`UPDATE invoice_counters SET last_number = ?, updated_at = datetime('now', 'localtime') WHERE type = 'purchase'`).run(newNumber);
          const formattedNumber = String(newNumber).padStart(counter.padding, '0');
          invoiceNumber = `${counter.prefix}${formattedNumber}`;
        } else {
          invoiceNumber = `PUR-${Date.now()}`;
        }
      } catch (e) {
        invoiceNumber = `PUR-${Date.now()}`;
      }
    }

    const transaction = db.transaction(() => {
      const invoiceResult = db.prepare(`
        INSERT INTO purchase_invoices (
          invoice_number, supplier_id, invoice_date, total_amount, 
          items_count, notes, status, user_id
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?)
      `).run(
        invoiceNumber,
        p.supplier_id || null,
        p.invoice_date || new Date().toISOString().split('T')[0],
        totalAmount,
        p.items.length,
        p.notes || null,
        'completed',
        authCheck.session.userId
      );

      const invoiceId = invoiceResult.lastInsertRowid;

      // ✅ دعم الإكسسوارات وقطع الصيانة
      const insertAccessoryItem = db.prepare(`
        INSERT INTO purchase_invoice_items (
          invoice_id, accessory_id, part_id, quantity, unit_price, total_price, notes
        ) VALUES (?, ?, ?, ?, ?, ?, ?)
      `);

      const insertRepairPartItem = db.prepare(`
        INSERT INTO purchase_invoice_items (
          invoice_id, accessory_id, part_id, quantity, unit_price, total_price, notes
        ) VALUES (?, ?, ?, ?, ?, ?, ?)
      `);

      const updateAccessoryStock = db.prepare(`
        UPDATE accessories 
        SET quantity = quantity + ?, 
            purchase_price = CASE WHEN ? > 0 THEN ? ELSE COALESCE(purchase_price, 0) END,
            updated_at = datetime('now', 'localtime')
        WHERE id = ?
      `);

      const updateRepairPartStock = db.prepare(`
        UPDATE repair_parts 
        SET qty = qty + ?, 
            unit_cost = ?,
            warehouse_id = COALESCE(?, warehouse_id)
        WHERE id = ?
      `);

      const insertAccessoryMovement = db.prepare(`
        INSERT INTO accessory_movements (
          accessory_id, type, quantity, quantity_before, quantity_after,
          unit_price, total_price, reference_type, reference_id,
          supplier_id, notes, reason, user_id
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
      `);

      const insertRepairPartMovement = db.prepare(`
        INSERT INTO repair_parts_movements (
          part_id, type, qty, unit_cost, note
        ) VALUES (?, ?, ?, ?, ?)
      `);

      for (const item of p.items) {
        const itemTotal = item.quantity * item.unit_price;
        const warehouseId = item.warehouse_id ? Number(item.warehouse_id) : null;
        
        if (item.accessory_id) {
          // ✅ معالجة الإكسسوارات
          insertAccessoryItem.run(
            invoiceId,
            item.accessory_id,
            null, // part_id = NULL للإكسسوارات
            item.quantity,
            item.unit_price,
            itemTotal,
            item.notes || null
          );

          const accessory = db.prepare(`SELECT quantity FROM accessories WHERE id = ?`).get(item.accessory_id);
          const quantityBefore = accessory ? accessory.quantity : 0;
          const quantityAfter = quantityBefore + item.quantity;

          updateAccessoryStock.run(item.quantity, item.unit_price, item.unit_price, item.accessory_id);

          // ✅ تحديث سعر البيع إذا تم تحديده
          if (item.new_sell_price != null && item.new_sell_price > 0) {
            db.prepare(`UPDATE accessories SET sell_price = ?, updated_at = datetime('now', 'localtime') WHERE id = ?`).run(item.new_sell_price, item.accessory_id);
          }

          // تحديث warehouse_id عند التوريد ليظهر الصنف في تفاصيل المخزن المختار
          if (warehouseId != null && !isNaN(warehouseId)) {
            db.prepare(`UPDATE accessories SET warehouse_id = ?, updated_at = datetime('now', 'localtime') WHERE id = ?`).run(warehouseId, item.accessory_id);
          }

          // ✅ إضافة معلومات المخزن في notes إذا كان موجوداً
          const movementNote = warehouseId 
            ? `فاتورة توريد ${invoiceNumber} (مخزن: ${warehouseId})`
            : `فاتورة توريد ${invoiceNumber}`;
          
          insertAccessoryMovement.run(
            item.accessory_id,
            'purchase',
            item.quantity,
            quantityBefore,
            quantityAfter,
            item.unit_price,
            itemTotal,
            'invoice',
            invoiceId,
            p.supplier_id || null,
            movementNote,
            'فاتورة توريد',
            authCheck.session.userId
          );
        } else if (item.part_id) {
          // ✅ معالجة قطع الصيانة
          // ✅ استخدام NULL لـ accessory_id لقطع الصيانة (بعد Migration 38.1)
          insertRepairPartItem.run(
            invoiceId,
            null, // accessory_id = NULL لقطع الصيانة
            item.part_id,
            item.quantity,
            item.unit_price,
            itemTotal,
            item.notes || null
          );

          const part = db.prepare(`SELECT qty, unit_cost FROM repair_parts WHERE id = ?`).get(item.part_id);
          const quantityBefore = part ? part.qty : 0;
          const quantityAfter = quantityBefore + item.quantity;
          const newUnitCost = item.unit_price > 0 ? item.unit_price : (part?.unit_cost || 0);

          updateRepairPartStock.run(item.quantity, newUnitCost, warehouseId, item.part_id);

          // ✅ تحديث سعر البيع إذا تم تحديده في الفاتورة
          if (item.new_sell_price != null && item.new_sell_price > 0) {
            db.prepare(`UPDATE repair_parts SET sell_price = ? WHERE id = ?`).run(item.new_sell_price, item.part_id);
          }

          const movementNote = `فاتورة توريد ${invoiceNumber}`;
          const finalNote = warehouseId ? `${movementNote} (مخزن: ${warehouseId})` : movementNote;

          insertRepairPartMovement.run(
            item.part_id,
            'in',
            item.quantity,
            newUnitCost,
            finalNote
          );
        }
      }

      return invoiceId;
    });

    const invoiceId = transaction();

    // ═══════════════════════════════════════════════════════════════
    // 💰 معالجة الدفع للخزنة والمورد
    // ═══════════════════════════════════════════════════════════════
    let balanceWarning = null;
    let supplierDebt = 0;
    let settlementAmount = 0;
    let walletBalanceAfter = null;
    const paidAmount = num(p.paid_amount, 0);
    const paymentMethod = p.payment_method || 'cash';
    const walletId = p.wallet_id ? parseInt(p.wallet_id) : null;
    
    if (totalAmount > 0) {
      // تحديد نوع المحفظة بناءً على طريقة الدفع
      const walletTypeMap = {
        cash: 'cash',
        mobile_wallet: 'mobile_wallet',
        bank: 'bank',
        deferred: null // الآجل لا يُخصم من أي محفظة
      };
      const walletType = walletTypeMap[paymentMethod] || 'cash';

      // تحويل payment_method للقيم المقبولة في الـ constraint
      const safePaymentMethodMap = {
        cash: 'cash',
        mobile_wallet: 'transfer', // المحفظة الإلكترونية تُسجل كـ transfer
        bank: 'transfer',          // البنك يُسجل كـ transfer
        deferred: 'cash'           // الآجل يُسجل كـ cash (لكن لن يُخصم)
      };
      const safePaymentMethod = safePaymentMethodMap[paymentMethod] || 'cash';

        // لو في مبلغ مدفوع وطريقة الدفع مش آجل - خصم من المحفظة المناسبة
        if (paidAmount > 0 && paymentMethod !== 'deferred') {
          const walletId = p.wallet_id ? parseInt(p.wallet_id) : null;
          
          // ✅ حساب رصيد المحفظة المحددة (إذا كان wallet_id موجوداً) أو كل المحافظ من نفس النوع
          let currentWalletBalance = 0;
          let walletName = '';
          
          if (walletId && (walletType === 'mobile_wallet' || walletType === 'bank')) {
            // ✅ حساب رصيد المحفظة المحددة فقط
            const deposits = db.prepare(`
              SELECT COALESCE(SUM(amount), 0) total FROM safe_transactions
              WHERE type IN ('deposit','sale') AND wallet_id = ?
            `).get(walletId).total || 0;
            const withdrawals = db.prepare(`
              SELECT COALESCE(SUM(amount), 0) total FROM safe_transactions
              WHERE type IN ('withdrawal','purchase','expense') AND wallet_id = ?
            `).get(walletId).total || 0;
            currentWalletBalance = deposits - withdrawals;
            
            // ✅ جلب اسم المحفظة المحددة
            const wallet = db.prepare(`SELECT name FROM payment_wallets WHERE id = ?`).get(walletId);
            walletName = wallet?.name || 'المحفظة المحددة';
          } else {
            // ✅ حساب رصيد كل المحافظ من نفس النوع (للتوافق مع الكاش)
            const deposits = db.prepare(`
              SELECT COALESCE(SUM(amount), 0) total FROM safe_transactions
              WHERE type IN ('deposit','sale') AND (wallet_type = ? OR (wallet_type IS NULL AND ? = 'cash'))
            `).get(walletType, walletType).total || 0;
            const withdrawals = db.prepare(`
              SELECT COALESCE(SUM(amount), 0) total FROM safe_transactions
              WHERE type IN ('withdrawal','purchase','expense') AND (wallet_type = ? OR (wallet_type IS NULL AND ? = 'cash'))
            `).get(walletType, walletType).total || 0;
            currentWalletBalance = deposits - withdrawals;
            
            const walletNames = { cash: 'الكاش', mobile_wallet: 'المحفظة الإلكترونية', bank: 'الحساب البنكي' };
            walletName = walletNames[walletType] || 'المحفظة';
          }

          if (currentWalletBalance < paidAmount) {
            balanceWarning = `تحذير: رصيد ${walletName} غير كافٍ! الرصيد الحالي: ${currentWalletBalance.toFixed(2)} ج.م، المطلوب: ${paidAmount.toFixed(2)} ج.م.`;
          }

          // ✅ تصنيف الخزنة حسب نوع الفاتورة: إكسسوارات فقط أم قطع صيانة فقط
          const hasAccessoryItems = db.prepare(`SELECT 1 FROM purchase_invoice_items WHERE invoice_id = ? AND accessory_id IS NOT NULL LIMIT 1`).get(invoiceId);
          const safeCategory = hasAccessoryItems ? 'مشتريات إكسسوارات' : 'مشتريات قطع صيانة';
          const safeDescription = hasAccessoryItems ? `فاتورة توريد إكسسوارات ${invoiceNumber}` : `فاتورة توريد قطع صيانة ${invoiceNumber}`;

          // ✅ إضافة للـ safe_transactions مع wallet_id المحدد
          db.prepare(`
            INSERT INTO safe_transactions(type, amount, category, description, payment_method, wallet_type, wallet_id, reference_type, reference_id, created_by)
            VALUES ('purchase', ?, ?, ?, ?, ?, ?, 'purchase_invoice', ?, 'system')
          `).run(paidAmount, safeCategory, safeDescription, safePaymentMethod, walletType, walletId, invoiceId);
        }

      // لو في مورد محدد - تسجيل في supplier_transactions
      if (p.supplier_id) {
        const supplier = db.prepare(`SELECT * FROM suppliers WHERE id = ?`).get(Number(p.supplier_id));
        const balanceBefore = parseFloat(supplier?.balance) || 0;

        // ✅ دعم التسوية: لو المدفوع أكبر من الفاتورة، الفائض يُخصم من الرصيد السابق
        const invoicePayment = Math.min(paidAmount, totalAmount); // المدفوع للفاتورة نفسها
        settlementAmount = paidAmount > totalAmount ? (paidAmount - totalAmount) : 0; // الفائض = تسوية

        // التحقق من أن مبلغ التسوية لا يتجاوز رصيد المورد
        if (settlementAmount > 0 && settlementAmount > balanceBefore) {
          return err(`مبلغ التسوية (${settlementAmount.toFixed(2)} ج.م) أكبر من رصيد المورد الحالي (${balanceBefore.toFixed(2)} ج.م)`, 400);
        }

        // المتبقي = الدين الجديد على المورد (فقط لو الفاتورة مش مدفوعة بالكامل)
        const remaining = totalAmount - invoicePayment;

        // لو في مبلغ متبقي - إضافة لرصيد المورد
        if (remaining > 0) {
          db.prepare(`UPDATE suppliers SET balance = balance + ? WHERE id = ?`).run(remaining, p.supplier_id);
          supplierDebt = remaining;
        }

        // لو في تسوية - خصم من رصيد المورد السابق
        if (settlementAmount > 0) {
          db.prepare(`UPDATE suppliers SET balance = balance - ? WHERE id = ?`).run(settlementAmount, p.supplier_id);
        }

        const balanceAfterInvoice = balanceBefore + remaining;
        const balanceAfterSettlement = balanceAfterInvoice - settlementAmount;

        // تحديد وصف الفاتورة حسب نوع الأصناف
        const hasAccessoryItems = p.items.some(i => i.accessory_id);
        const invoiceTypeLabel = hasAccessoryItems ? 'إكسسوارات' : 'قطع صيانة';

        // تسجيل الفاتورة كاملة في supplier_transactions (المشتريات)
        db.prepare(`
          INSERT INTO supplier_transactions(supplier_id, type, amount, balance_before, balance_after, payment_method, reference_type, reference_id, notes, created_by)
          VALUES (?, 'purchase', ?, ?, ?, ?, 'purchase_invoice', ?, ?, 'system')
        `).run(
          p.supplier_id,
          totalAmount,
          balanceBefore,
          balanceAfterInvoice,
          paymentMethod,
          invoiceId,
          `فاتورة ${invoiceTypeLabel} #${invoiceNumber}`
        );

        // لو في مبلغ مدفوع - تسجيل السداد (المبلغ المدفوع للفاتورة فقط)
        if (invoicePayment > 0) {
          db.prepare(`
            INSERT INTO supplier_transactions(supplier_id, type, amount, balance_before, balance_after, payment_method, reference_type, reference_id, notes, created_by)
            VALUES (?, 'payment', ?, ?, ?, ?, 'purchase_invoice', ?, ?, 'system')
          `).run(
            p.supplier_id,
            invoicePayment,
            balanceAfterInvoice,
            balanceAfterInvoice, // الرصيد نفسه لأن المدفوع خُصم من الفاتورة مباشرة
            paymentMethod,
            invoiceId,
            `سداد فاتورة #${invoiceNumber}`
          );
        }

        // ✅ لو في تسوية - تسجيل معاملة تسوية منفصلة
        if (settlementAmount > 0) {
          db.prepare(`
            INSERT INTO supplier_transactions(supplier_id, type, amount, balance_before, balance_after, payment_method, reference_type, reference_id, notes, created_by)
            VALUES (?, 'payment', ?, ?, ?, ?, 'purchase_invoice', ?, ?, 'system')
          `).run(
            p.supplier_id,
            settlementAmount,
            balanceAfterInvoice,
            balanceAfterSettlement,
            paymentMethod,
            invoiceId,
            `تسوية رصيد سابق مع فاتورة #${invoiceNumber}`
          );
        }
      }

      // تحديث الفاتورة بالمبلغ المدفوع (المبلغ المدفوع للفاتورة فقط، بدون التسوية)
      const invoicePaidOnly = Math.min(paidAmount, totalAmount);
      db.prepare(`UPDATE purchase_invoices SET paid_amount = ?, payment_method = ? WHERE id = ?`)
        .run(invoicePaidOnly, paymentMethod, invoiceId);
    }

    // ✅ حساب رصيد المحفظة المحددة بعد التوريد
    if (paidAmount > 0 && paymentMethod !== 'deferred' && walletId && (paymentMethod === 'mobile_wallet' || paymentMethod === 'bank')) {
      const deposits = db.prepare(`
        SELECT COALESCE(SUM(amount), 0) total FROM safe_transactions
        WHERE type IN ('deposit','sale') AND wallet_id = ?
      `).get(walletId).total || 0;
      const withdrawals = db.prepare(`
        SELECT COALESCE(SUM(amount), 0) total FROM safe_transactions
        WHERE type IN ('withdrawal','purchase','expense') AND wallet_id = ?
      `).get(walletId).total || 0;
      walletBalanceAfter = deposits - withdrawals;
    }

    logAudit('PURCHASE_INVOICE_CREATED', {
      id: invoiceId,
      invoice_number: invoiceNumber,
      items_count: p.items.length,
      total_amount: totalAmount,
      paid_amount: paidAmount,
      supplier_id: p.supplier_id
    }, authCheck.session.userId);

    return json({
      ok: true,
      invoice_id: invoiceId,
      invoice_number: invoiceNumber,
      balanceWarning: balanceWarning,
      supplierDebt: supplierDebt,
      settlementAmount: settlementAmount || 0,
      walletBalanceAfter: walletBalanceAfter
    });

  } catch (error) {
    console.error('[PURCHASE-INVOICES] Error creating:', error);
    return err('فشل إنشاء الفاتورة: ' + error.message, 500);
  }
}

// PUT /purchase-invoices/:id/cancel - إلغاء فاتورة
if (route.match(/^purchase-invoices\/\d+\/cancel$/) && req.method === 'PUT') {
  const authCheck = requireAuth(req, route);
  if (!authCheck.authorized) return err(authCheck.error, authCheck.code);

  const permCheck = requirePermission(authCheck.session, 'accessories', 'write');
  if (!permCheck.authorized) return err(permCheck.error, permCheck.code);

  try {
    const id = posInt(route.split('/')[1], 'رقم الفاتورة غير صحيح');

    const invoice = db.prepare(`SELECT * FROM purchase_invoices WHERE id = ?`).get(id);
    if (!invoice) {
      return err('الفاتورة غير موجودة', 404);
    }

    if (invoice.status === 'cancelled') {
      return err('الفاتورة ملغية بالفعل', 400);
    }

    const items = db.prepare(`SELECT * FROM purchase_invoice_items WHERE invoice_id = ?`).all(id);

    const transaction = db.transaction(() => {
      const updateStock = db.prepare(`
        UPDATE accessories 
        SET quantity = quantity - ?,
            updated_at = datetime('now', 'localtime')
        WHERE id = ?
      `);

      const insertMovement = db.prepare(`
        INSERT INTO accessory_movements (
          accessory_id, type, quantity, quantity_before, quantity_after,
          unit_price, total_price, reference_type, reference_id,
          notes, reason, user_id
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
      `);

      for (const item of items) {
        const accessory = db.prepare(`SELECT quantity FROM accessories WHERE id = ?`).get(item.accessory_id);
        const quantityBefore = accessory ? accessory.quantity : 0;
        const quantityAfter = quantityBefore - item.quantity;

        updateStock.run(item.quantity, item.accessory_id);

        insertMovement.run(
          item.accessory_id,
          'cancel',
          -item.quantity,
          quantityBefore,
          quantityAfter,
          item.unit_price,
          item.total_price,
          'invoice_cancel',
          id,
          `إلغاء فاتورة ${invoice.invoice_number}`,
          'إلغاء فاتورة توريد',
          authCheck.session.userId
        );
      }

      db.prepare(`
        UPDATE purchase_invoices 
        SET status = 'cancelled', updated_at = datetime('now', 'localtime')
        WHERE id = ?
      `).run(id);
    });

    transaction();

    logAudit('PURCHASE_INVOICE_CANCELLED', {
      id,
      invoice_number: invoice.invoice_number
    }, authCheck.session.userId);

    return json({
      success: true,
      message: 'تم إلغاء الفاتورة بنجاح'
    });

  } catch (error) {
    console.error('[PURCHASE-INVOICES] Error cancelling:', error);
    return err('فشل إلغاء الفاتورة: ' + error.message, 500);
  }
}

// DELETE /purchase-invoices/:id - حذف فاتورة مع عكس كل العمليات المحاسبية (للمديرين فقط)
if (route.match(/^purchase-invoices\/\d+$/) && req.method === 'DELETE') {
  const authCheck = requireAuth(req, route);
  if (!authCheck.authorized) return err(authCheck.error, authCheck.code);

  const adminCheck = requireAdmin(authCheck.session);
  if (!adminCheck.authorized) return err(adminCheck.error, adminCheck.code);

  try {
    const id = posInt(route.split('/')[1], 'رقم الفاتورة غير صحيح');

    const invoice = db.prepare(`SELECT * FROM purchase_invoices WHERE id = ?`).get(id);
    if (!invoice) {
      return err('الفاتورة غير موجودة', 404);
    }

    // جلب أصناف الفاتورة
    const items = db.prepare(`SELECT * FROM purchase_invoice_items WHERE invoice_id = ?`).all(id);

    const transaction = db.transaction(() => {
      // ═══════════════════════════════════════════════════════════════
      // 1️⃣ عكس المخزون - إرجاع الكميات
      // ═══════════════════════════════════════════════════════════════
      for (const item of items) {
        if (item.accessory_id) {
          // إكسسوار - تقليل الكمية
          db.prepare(`UPDATE accessories SET quantity = quantity - ? WHERE id = ?`).run(item.quantity, item.accessory_id);

          // حذف حركة المخزون المرتبطة
          db.prepare(`DELETE FROM accessory_movements WHERE reference_type = 'invoice' AND reference_id = ? AND accessory_id = ?`).run(id, item.accessory_id);
        } else if (item.part_id) {
          // قطعة صيانة - تقليل الكمية
          db.prepare(`UPDATE repair_parts SET qty = qty - ? WHERE id = ?`).run(item.quantity, item.part_id);

          // حذف حركة المخزون المرتبطة
          db.prepare(`DELETE FROM repair_parts_movements WHERE note LIKE ? AND part_id = ?`).run(`%فاتورة توريد ${invoice.invoice_number}%`, item.part_id);
        }
      }

      // ═══════════════════════════════════════════════════════════════
      // 2️⃣ عكس حركات الخزنة
      // ═══════════════════════════════════════════════════════════════
      db.prepare(`DELETE FROM safe_transactions WHERE reference_type = 'purchase_invoice' AND reference_id = ?`).run(id);

      // ═══════════════════════════════════════════════════════════════
      // 3️⃣ عكس رصيد المورد
      // ═══════════════════════════════════════════════════════════════
      if (invoice.supplier_id) {
        // جلب معاملة المورد المرتبطة
        const supplierTx = db.prepare(`
          SELECT * FROM supplier_transactions
          WHERE reference_type = 'purchase_invoice' AND reference_id = ? AND type = 'purchase'
        `).get(id);

        if (supplierTx) {
          // حساب المبلغ المستحق الذي تم إضافته (الفرق بين balance_after و balance_before)
          const debtAdded = (supplierTx.balance_after || 0) - (supplierTx.balance_before || 0);

          // إرجاع الدين من رصيد المورد
          if (debtAdded > 0) {
            db.prepare(`UPDATE suppliers SET balance = balance - ? WHERE id = ?`).run(debtAdded, invoice.supplier_id);
          }
        }

        // حذف معاملات المورد المرتبطة
        db.prepare(`DELETE FROM supplier_transactions WHERE reference_type = 'purchase_invoice' AND reference_id = ?`).run(id);
      }

      // ═══════════════════════════════════════════════════════════════
      // 4️⃣ حذف أصناف الفاتورة
      // ═══════════════════════════════════════════════════════════════
      db.prepare(`DELETE FROM purchase_invoice_items WHERE invoice_id = ?`).run(id);

      // ═══════════════════════════════════════════════════════════════
      // 5️⃣ حذف الفاتورة نفسها
      // ═══════════════════════════════════════════════════════════════
      db.prepare(`DELETE FROM purchase_invoices WHERE id = ?`).run(id);
    });

    transaction();

    logAudit('PURCHASE_INVOICE_DELETED_WITH_REVERSAL', {
      id,
      invoice_number: invoice.invoice_number,
      items_count: items.length,
      total_amount: invoice.total_amount,
      supplier_id: invoice.supplier_id
    }, authCheck.session.userId);

    return json({
      success: true,
      message: `تم حذف الفاتورة ${invoice.invoice_number} وعكس جميع العمليات المحاسبية`,
      reversed: {
        items: items.length,
        total: invoice.total_amount
      }
    });

  } catch (error) {
    console.error('[PURCHASE-INVOICES] Error deleting:', error);
    return err('فشل حذف الفاتورة: ' + error.message, 500);
  }
}

// DELETE /accessory-movements/:id - حذف توريد سريع مع عكس كل العمليات المحاسبية (للمديرين فقط)
if (route.match(/^accessory-movements\/\d+$/) && req.method === 'DELETE') {
  const authCheck = requireAuth(req, route);
  if (!authCheck.authorized) return err(authCheck.error, authCheck.code);

  const adminCheck = requireAdmin(authCheck.session);
  if (!adminCheck.authorized) return err(adminCheck.error, adminCheck.code);

  try {
    const id = posInt(route.split('/')[1], 'رقم الحركة غير صحيح');

    const movement = db.prepare(`SELECT * FROM accessory_movements WHERE id = ? AND type = 'purchase'`).get(id);
    if (!movement) {
      return err('حركة التوريد غير موجودة', 404);
    }

    // جلب بيانات الإكسسوار
    const accessory = db.prepare(`SELECT * FROM accessories WHERE id = ?`).get(movement.accessory_id);
    if (!accessory) {
      return err('الإكسسوار غير موجود', 404);
    }

    const transaction = db.transaction(() => {
      // ═══════════════════════════════════════════════════════════════
      // 1️⃣ عكس المخزون - تقليل الكمية
      // ═══════════════════════════════════════════════════════════════
      db.prepare(`UPDATE accessories SET quantity = quantity - ? WHERE id = ?`).run(movement.quantity, movement.accessory_id);

      // ═══════════════════════════════════════════════════════════════
      // 2️⃣ عكس حركات الخزنة
      // ═══════════════════════════════════════════════════════════════
      db.prepare(`DELETE FROM safe_transactions WHERE reference_type = 'accessory_movement' AND reference_id = ?`).run(id);

      // ═══════════════════════════════════════════════════════════════
      // 3️⃣ عكس رصيد المورد
      // ═══════════════════════════════════════════════════════════════
      if (movement.supplier_id) {
        // جلب معاملة المورد المرتبطة
        const supplierTx = db.prepare(`
          SELECT * FROM supplier_transactions
          WHERE reference_type = 'quick_purchase' AND reference_id = ? AND type = 'purchase'
        `).get(id);

        if (supplierTx) {
          // حساب المبلغ المستحق الذي تم إضافته
          const debtAdded = (supplierTx.balance_after || 0) - (supplierTx.balance_before || 0);

          // إرجاع الدين من رصيد المورد
          if (debtAdded > 0) {
            db.prepare(`UPDATE suppliers SET balance = balance - ? WHERE id = ?`).run(debtAdded, movement.supplier_id);
          }
        }

        // حذف معاملات المورد المرتبطة
        db.prepare(`DELETE FROM supplier_transactions WHERE reference_type = 'quick_purchase' AND reference_id = ?`).run(id);
      }

      // ═══════════════════════════════════════════════════════════════
      // 4️⃣ حذف حركة التوريد نفسها
      // ═══════════════════════════════════════════════════════════════
      db.prepare(`DELETE FROM accessory_movements WHERE id = ?`).run(id);
    });

    transaction();

    logAudit('QUICK_PURCHASE_DELETED_WITH_REVERSAL', {
      id,
      accessory_id: movement.accessory_id,
      accessory_name: accessory.name,
      quantity: movement.quantity,
      total_price: movement.total_price,
      supplier_id: movement.supplier_id
    }, authCheck.session.userId);

    return json({
      success: true,
      message: `تم حذف التوريد السريع للـ ${accessory.name} وعكس جميع العمليات المحاسبية`,
      reversed: {
        quantity: movement.quantity,
        total: movement.total_price
      }
    });

  } catch (error) {
    console.error('[ACCESSORY-MOVEMENTS] Error deleting:', error);
    return err('فشل حذف التوريد: ' + error.message, 500);
  }
}

// ═══════════════════════════════════════════════════════════════════
// 📥 شراء جهاز من زبون (POS Customer Purchase)
// ═══════════════════════════════════════════════════════════════════

// GET /cash-drawer-balance - رصيد درج الكاش الحالي (الفلوس النقدية في يد الكاشير)
if (route === 'cash-drawer-balance' && req.method === 'GET') {
  try {
    // درج الكاش = الفلوس النقدية في نقطة البيع من cash_ledger
    // نفس المنطق المستخدم في loadCashDrawerData() في pos.js

    const today = new Date().toISOString().split('T')[0];
    const afterTime = params.get('after') || null; // وقت آخر تقفيل شفت

    // العمليات التي نتجاهلها (محسوبة من مصادر أخرى أو ليست عمليات POS)
    const ignoredRefs = [
      'sale', 'accessory_sale', 'purchase', 'device_purchase',
      'accessory_purchase', 'accessory_invoice'
    ];

    // مرتجعات التوريد (تذهب للخزنة الرئيسية وليس درج الكاش)
    const purchaseReturnRefs = [
      'accessory_return', 'purchase_return_settlement',
      'invoice_return', 'quick_return'
    ];

    // جلب كل عمليات cash_ledger لليوم
    const ledgerTx = db.prepare(`
      SELECT * FROM cash_ledger
      WHERE date(created_at) = ?
    `).all(today);

    let depositsTotal = 0;
    let withdrawsTotal = 0;
    let safeWithdrawsTotal = 0;
    let posPurchasesTotal = 0;

    const closingTimestamp = afterTime ? new Date(afterTime).getTime() : 0;

    ledgerTx.forEach(tx => {
      // فلتر بوقت آخر تقفيل شفت
      if (afterTime && tx.created_at) {
        let txDateTime = tx.created_at;
        if (!txDateTime.includes('T')) {
          txDateTime = txDateTime.replace(' ', 'T') + 'Z';
        }
        if (new Date(txDateTime).getTime() <= closingTimestamp) {
          return; // تجاهل العمليات قبل آخر تقفيل
        }
      }

      // تجاهل عمليات البيع والمشتريات من الموردين
      if (ignoredRefs.includes(tx.ref)) return;
      if (tx.ref && tx.ref.startsWith('accessory_sale_')) return;
      if (tx.ref && tx.ref.startsWith('supplier_payment_')) return;

      // تجاهل مرتجعات التوريد (kind='in' مع ref من نوع return)
      if (tx.kind === 'in' && tx.ref && (
          purchaseReturnRefs.includes(tx.ref) ||
          tx.ref.includes('purchase_return') ||
          tx.ref.includes('_return')
      )) {
        return;
      }

      if (tx.kind === 'in') {
        if (tx.ref === 'safe_withdraw') {
          safeWithdrawsTotal += Number(tx.amount || 0);
        } else {
          depositsTotal += Number(tx.amount || 0);
        }
      } else if (tx.kind === 'out') {
        if (tx.ref === 'pos_purchase') {
          posPurchasesTotal += Number(tx.amount || 0);
        } else {
          withdrawsTotal += Number(tx.amount || 0);
        }
      }
    });

    // جلب مبيعات الأجهزة النقدية لليوم (بعد آخر تقفيل إن وُجد)
    let deviceSalesCash = 0;
    if (afterTime) {
      deviceSalesCash = db.prepare(`
        SELECT COALESCE(SUM(paid_now), 0) as total
        FROM sales
        WHERE date(created_at) = ?
          AND created_at > ?
          AND status = 'completed'
          AND (payment_method = 'cash' OR payment_method IS NULL)
      `).get(today, afterTime).total || 0;
    } else {
      deviceSalesCash = db.prepare(`
        SELECT COALESCE(SUM(paid_now), 0) as total
        FROM sales
        WHERE date(created_at) = ?
          AND status = 'completed'
          AND (payment_method = 'cash' OR payment_method IS NULL)
      `).get(today).total || 0;
    }

    // جلب مبيعات الإكسسوارات النقدية لليوم (بعد آخر تقفيل إن وُجد)
    let accessorySalesCash = 0;
    if (afterTime) {
      accessorySalesCash = db.prepare(`
        SELECT COALESCE(SUM(total_price), 0) as total
        FROM accessory_movements
        WHERE date(created_at) = ?
          AND created_at > ?
          AND type = 'sale'
          AND (payment_method = 'cash' OR payment_method IS NULL)
      `).get(today, afterTime).total || 0;
    } else {
      accessorySalesCash = db.prepare(`
        SELECT COALESCE(SUM(total_price), 0) as total
        FROM accessory_movements
        WHERE date(created_at) = ?
          AND type = 'sale'
          AND (payment_method = 'cash' OR payment_method IS NULL)
      `).get(today).total || 0;
    }

    // رصيد الدرج = مبيعات نقدية + إيداعات + سحب من الخزنة - مسحوبات - مشتريات POS
    const balance = deviceSalesCash + accessorySalesCash + depositsTotal + safeWithdrawsTotal - withdrawsTotal - posPurchasesTotal;

    return json({ balance });
  } catch (error) {
    console.error('[CASH-DRAWER] Error getting balance:', error);
    return err('فشل جلب رصيد الدرج', 500);
  }
}

// ═══════════════════════════════════════════════════════════════
// 🔧 POST /fix-old-returns - تصحيح المرتجعات القديمة بدون user_id
// ═══════════════════════════════════════════════════════════════
if (route === 'fix-old-returns' && req.method === 'POST') {
  const authCheck = requireAuth(req, route);
  if (!authCheck.authorized) return err(authCheck.error, authCheck.code);

  // فقط الأدمن يمكنه تشغيل هذا
  if (authCheck.session.role !== 'admin') {
    return err('هذه العملية متاحة للمدير فقط', 403);
  }

  try {
    const p = await body(req);
    const targetUserId = p.user_id ? parseInt(p.user_id) : null;
    const targetUsername = p.username || null;

    if (!targetUserId) {
      return err('يجب تحديد user_id للمستخدم', 400);
    }

    // البحث عن المرتجعات بدون user_id
    const oldReturns = db.prepare(`
      SELECT id, ref, amount, note, wallet_type, wallet_id, created_at
      FROM cash_ledger
      WHERE (ref = 'return' OR ref = 'accessory_return')
        AND user_id IS NULL
    `).all();

    console.log('[FIX-OLD-RETURNS] Found', oldReturns.length, 'returns without user_id');

    if (oldReturns.length === 0) {
      return json({
        ok: true,
        message: 'لا توجد مرتجعات قديمة بحاجة للتصحيح',
        fixed: 0
      });
    }

    // تحديث المرتجعات بـ user_id
    const updateStmt = db.prepare(`
      UPDATE cash_ledger
      SET user_id = ?, username = ?
      WHERE id = ?
    `);

    let fixedCount = 0;
    const tx = db.transaction(() => {
      oldReturns.forEach(ret => {
        updateStmt.run(targetUserId, targetUsername, ret.id);
        fixedCount++;
        console.log('[FIX-OLD-RETURNS] Fixed:', ret.id, ret.ref, ret.amount, '-> user_id:', targetUserId);
      });
    });

    tx();

    logAudit('FIX_OLD_RETURNS', {
      fixed_count: fixedCount,
      target_user_id: targetUserId,
      target_username: targetUsername
    }, authCheck.session.userId);

    return json({
      ok: true,
      message: `تم تصحيح ${fixedCount} مرتجع قديم`,
      fixed: fixedCount,
      details: oldReturns.map(r => ({
        id: r.id,
        ref: r.ref,
        amount: r.amount,
        date: r.created_at
      }))
    });

  } catch (error) {
    console.error('[FIX-OLD-RETURNS] Error:', error);
    return err('فشل تصحيح المرتجعات: ' + error.message, 500);
  }
}

// GET /old-returns-status - عرض حالة المرتجعات القديمة
if (route === 'old-returns-status' && req.method === 'GET') {
  const authCheck = requireAuth(req, route);
  if (!authCheck.authorized) return err(authCheck.error, authCheck.code);

  try {
    // المرتجعات بدون user_id
    const oldReturns = db.prepare(`
      SELECT id, ref, amount, note, wallet_type, wallet_id, kind, created_at
      FROM cash_ledger
      WHERE (ref = 'return' OR ref = 'accessory_return')
        AND user_id IS NULL
      ORDER BY created_at DESC
    `).all();

    // المرتجعات مع user_id
    const fixedReturns = db.prepare(`
      SELECT id, ref, amount, note, wallet_type, user_id, username, created_at
      FROM cash_ledger
      WHERE (ref = 'return' OR ref = 'accessory_return')
        AND user_id IS NOT NULL
      ORDER BY created_at DESC
      LIMIT 20
    `).all();

    // قائمة المستخدمين للاختيار
    const users = db.prepare(`
      SELECT id, username, full_name, role
      FROM users
      WHERE is_active = 1
      ORDER BY username
    `).all();

    return json({
      needs_fix: oldReturns.length,
      old_returns: oldReturns,
      recent_fixed: fixedReturns,
      users: users
    });

  } catch (error) {
    console.error('[OLD-RETURNS-STATUS] Error:', error);
    return err('فشل جلب حالة المرتجعات', 500);
  }
}

// GET /drawer-wallets-balance - أرصدة كل المحافظ في درج الكاش
if (route === 'drawer-wallets-balance' && req.method === 'GET') {
  try {
    // 🔧 استخدام التاريخ المحلي بدل UTC عشان يتوافق مع SQLite
    const now = new Date();
    const today = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
    let afterTime = url.searchParams.get('after') || null;
    // ✅ v1.2.5: Per-User Filter - كل كاشير يرى أرصدة درجه فقط
    const filterUserId = url.searchParams.get('user_id');
    console.log('[DRAWER-WALLETS] 🔐 user_id filter:', filterUserId || 'NONE (showing all)');

    // تحويل afterTime لصيغة SQLite datetime - بدون تحويل UTC!
    // ⚠️ مهم: الأوقات في SQLite مخزنة بـ local time، فلازم نحافظ على الـ local time
    if (afterTime) {
      // لو الوقت بصيغة 'YYYY-MM-DD HH:MM:SS' أو 'YYYY-MM-DDTHH:MM:SS' نستخدمه مباشرة
      // بدون تحويل لـ UTC
      afterTime = afterTime.replace('T', ' ').replace('Z', '').slice(0, 19);
      console.log('[DRAWER-WALLETS] afterTime (cleaned, local):', afterTime);
    }
    console.log('[DRAWER-WALLETS] today:', today, 'afterTime:', afterTime);

    // ✅ v1.2.5: Build user filter for SQL
    // userFilterSQL for queries with 'cl' alias, userFilterSQLNoAlias for queries without alias
    const userFilterSQL = filterUserId ? 'AND cl.user_id = ?' : '';
    const userFilterSQLNoAlias = filterUserId ? 'AND user_id = ?' : '';
    const userFilterParams = filterUserId ? [Number(filterUserId)] : [];

    // 🔧 جلب مبيعات الأجهزة من cash_ledger بدل sales
    // لأن cash_ledger هو المصدر الموثوق للحركات المالية الفعلية
    // ✅ دعم wallet_id و wallet_type للتوافق العكسي
    // ✅ FIX: لو مفيش afterTime (مفيش تقفيل سابق)، نجيب كل الحركات من البداية بدل اليوم بس
    const salesParams = afterTime ? [afterTime, ...userFilterParams] : [...userFilterParams];
    let deviceSalesQuery = `
      SELECT
        COALESCE(pw.type, cl.wallet_type, 'cash') as wallet_type,
        COALESCE(SUM(cl.amount), 0) as total
      FROM cash_ledger cl
      LEFT JOIN payment_wallets pw ON cl.wallet_id = pw.id
      WHERE cl.ref = 'sale'
        ${afterTime
          ? "AND datetime(cl.created_at) > datetime(?)"
          : ""}
        ${userFilterSQL}
      GROUP BY COALESCE(pw.type, cl.wallet_type, 'cash')
    `;
    const deviceSales = db.prepare(deviceSalesQuery).all(...salesParams);
    console.log('[DRAWER-WALLETS] salesParams:', salesParams);
    console.log('[DRAWER-WALLETS] Device sales from cash_ledger:', deviceSales);

    // جلب مبيعات الإكسسوارات مقسمة حسب طريقة الدفع
    // ✅ لو فيه afterTime نجيب بس اللي بعده، ولو مفيش نجيب اليوم
    // ✅ v1.2.5: Per-User Filter
    const accUserFilterSQL = filterUserId ? 'AND user_id = ?' : '';
    // ✅ FIX: لو مفيش afterTime، نجيب كل الحركات من البداية
    const accSalesParams = afterTime ? [afterTime, ...userFilterParams] : [...userFilterParams];
    let accessorySalesQuery = `
      SELECT
        payment_method,
        COALESCE(SUM(total_price), 0) as total
      FROM accessory_movements
      WHERE type = 'sale'
        AND (status IS NULL OR status IN ('completed', 'returned'))
        ${afterTime
          ? "AND datetime(created_at) > datetime(?)"
          : ""}
        ${accUserFilterSQL}
      GROUP BY payment_method
    `;
    const accessorySales = db.prepare(accessorySalesQuery).all(...accSalesParams);

    // ✅ جلب جميع المحافظ الفعلية من payment_wallets
    const allWallets = db.prepare(`
      SELECT id, name, type, is_default, is_active
      FROM payment_wallets
      WHERE is_active = 1
      ORDER BY type, is_default DESC, name
    `).all();
    
    // إنشاء خريطة للأرصدة لكل محفظة (wallet_id)
    const walletBalances = {};
    allWallets.forEach(w => {
      walletBalances[w.id] = {
        id: w.id,
        name: w.name,
        type: w.type,
        is_default: w.is_default,
        balance: 0,
        sales: 0  // ✅ مبيعات كل محفظة على حدة
      };
    });
    
    // ✅ تجميع المبيعات حسب wallet_id (وليس wallet_type فقط)
    // مبيعات الأجهزة (من cash_ledger - wallet_id مباشرة)
    // ✅ v1.2.5: Per-User Filter
    console.log('[DRAWER-WALLETS] Device sales rows:', deviceSales);
    const deviceSalesByWallet = db.prepare(`
      SELECT
        COALESCE(cl.wallet_id, pw.id) as wallet_id,
        pw.id as wallet_id_from_table,
        pw.name as wallet_name,
        pw.type as wallet_type,
        COALESCE(SUM(cl.amount), 0) as total
      FROM cash_ledger cl
      LEFT JOIN payment_wallets pw ON (
        cl.wallet_id = pw.id OR
        (cl.wallet_id IS NULL AND pw.type = cl.wallet_type AND pw.is_default = 1)
      )
      WHERE cl.ref = 'sale'
        ${afterTime
          ? "AND datetime(cl.created_at) > datetime(?)"
          : ""}
        ${userFilterSQL}
      GROUP BY COALESCE(cl.wallet_id, pw.id)
    `).all(...salesParams);
    
    console.log('[DRAWER-WALLETS] deviceSalesByWallet raw:', JSON.stringify(deviceSalesByWallet));
    deviceSalesByWallet.forEach(row => {
      console.log('[DRAWER-WALLETS] Device sale row:', row.wallet_id, row.wallet_name, row.total);
      const walletId = row.wallet_id;
      if (walletId && walletBalances[walletId]) {
        walletBalances[walletId].balance += Number(row.total || 0);
        walletBalances[walletId].sales += Number(row.total || 0);  // ✅ مبيعات per wallet
      } else if (row.wallet_type) {
        // Fallback: تجميع حسب النوع للتوافق العكسي
        allWallets.forEach(w => {
          if (w.type === row.wallet_type && w.is_default) {
            walletBalances[w.id].balance += Number(row.total || 0);
            walletBalances[w.id].sales += Number(row.total || 0);  // ✅ مبيعات per wallet
          }
        });
      }
    });
    console.log('[DRAWER-WALLETS] After device sales by wallet - sales breakdown:', Object.values(walletBalances).map(w => `${w.name}: balance=${w.balance}, sales=${w.sales}`));

    // مبيعات الإكسسوارات - تجميع حسب wallet_id من cash_ledger
    // ✅ v1.2.5: Per-User Filter
    const accessorySalesByWallet = db.prepare(`
      SELECT
        COALESCE(cl.wallet_id, pw.id) as wallet_id,
        pw.id as wallet_id_from_table,
        pw.name as wallet_name,
        pw.type as wallet_type,
        COALESCE(SUM(cl.amount), 0) as total
      FROM cash_ledger cl
      LEFT JOIN payment_wallets pw ON (
        cl.wallet_id = pw.id OR
        (cl.wallet_id IS NULL AND pw.type = cl.wallet_type AND pw.is_default = 1)
      )
      WHERE cl.ref LIKE 'accessory_sale_%'
        ${afterTime
          ? "AND datetime(cl.created_at) > datetime(?)"
          : ""}
        ${userFilterSQL}
      GROUP BY COALESCE(cl.wallet_id, pw.id)
    `).all(...salesParams);
    
    console.log('[DRAWER-WALLETS] accessorySalesByWallet raw:', JSON.stringify(accessorySalesByWallet));
    accessorySalesByWallet.forEach(row => {
      console.log('[DRAWER-WALLETS] Accessory sale row:', row.wallet_id, row.wallet_name, row.total);
      const walletId = row.wallet_id;
      if (walletId && walletBalances[walletId]) {
        walletBalances[walletId].balance += Number(row.total || 0);
        walletBalances[walletId].sales += Number(row.total || 0);  // ✅ مبيعات per wallet
      } else if (row.wallet_type) {
        // Fallback: تجميع حسب النوع للتوافق العكسي
        allWallets.forEach(w => {
          if (w.type === row.wallet_type && w.is_default) {
            walletBalances[w.id].balance += Number(row.total || 0);
            walletBalances[w.id].sales += Number(row.total || 0);  // ✅ مبيعات per wallet
          }
        });
      }
    });
    console.log('[DRAWER-WALLETS] After accessory sales by wallet - sales breakdown:', Object.values(walletBalances).map(w => `${w.name}: balance=${w.balance}, sales=${w.sales}`));

    // جلب عمليات cash_ledger (بعد آخر تقفيل أو كل الحركات لو مفيش تقفيل)
    // ✅ v1.2.5: Per-User Filter - using userFilterSQLNoAlias since no table alias
    // ✅ FIX: لو مفيش afterTime، نجيب كل الحركات من البداية بدل اليوم بس
    let ledgerQuery, ledgerParams;
    if (afterTime) {
      ledgerQuery = `SELECT * FROM cash_ledger WHERE datetime(created_at) > datetime(?) ${userFilterSQLNoAlias}`;
      ledgerParams = [afterTime, ...userFilterParams];
    } else {
      ledgerQuery = `SELECT * FROM cash_ledger WHERE 1=1 ${userFilterSQLNoAlias}`;
      ledgerParams = [...userFilterParams];
    }
    const ledgerTx = db.prepare(ledgerQuery).all(...ledgerParams);

    // ✅ تجاهل عمليات المبيعات والمشتريات (محسوبة من جداولها)
    // ⚠️ المرتجعات (return, accessory_return) تبقى لأن المبيعات المرتجعة محسوبة في المبيعات
    // ⚠️ wallet_transfer = تحويل داخلي بين محافظ الدرج - لا يؤثر على الخزينة
    const ignoredRefs = ['sale', 'accessory_sale', 'purchase', 'device_purchase', 'accessory_purchase', 'accessory_invoice', 'wallet_transfer'];
    // تجاهل مرتجعات التوريد فقط (فلوس داخلة من الموردين - لا علاقة لها بدرج الكاش)
    const purchaseReturnRefs = ['purchase_return_settlement', 'invoice_return', 'quick_return'];

    ledgerTx.forEach(tx => {
      if (ignoredRefs.includes(tx.ref)) return;
      if (tx.ref && tx.ref.startsWith('accessory_sale_')) return;
      if (tx.ref && tx.ref.startsWith('supplier_payment_')) return;

      // تجاهل مرتجعات التوريد (kind='in' = فلوس داخلة من المورد)
      // ⚠️ مرتجعات المبيعات تكون kind='out' (فلوس خارجة للعميل) - لا نتجاهلها!
      if (tx.kind === 'in' && tx.ref && (
          purchaseReturnRefs.includes(tx.ref) ||
          tx.ref.includes('purchase_return')
      )) {
        return;
      }

      // ✅ Log مرتجعات المبيعات للتتبع
      if (tx.kind === 'out' && tx.ref && (tx.ref === 'return' || tx.ref === 'accessory_return')) {
        console.log('[DRAWER-WALLETS] 📦 Found sales return:', tx.ref, 'amount:', tx.amount, 'wallet_id:', tx.wallet_id, 'wallet_type:', tx.wallet_type);
      }

      // ✅ تحديد wallet_id و wallet_type
      let walletId = tx.wallet_id;
      let walletType = 'cash';
      
      if (walletId) {
        const wallet = db.prepare(`SELECT type, name FROM payment_wallets WHERE id = ?`).get(walletId);
        if (wallet) {
          walletType = wallet.type;
        } else {
          walletId = null; // المحفظة غير موجودة
          walletType = tx.wallet_type || 'cash';
        }
      } else {
        walletType = tx.wallet_type || 'cash';
        // محاولة الحصول على المحفظة الافتراضية لهذا النوع
        const defaultWallet = db.prepare(`
          SELECT id FROM payment_wallets 
          WHERE type = ? AND is_default = 1 AND is_active = 1
          LIMIT 1
        `).get(walletType);
        if (defaultWallet) {
          walletId = defaultWallet.id;
        }
      }

      // إذا لم نجد wallet_id، نستخدم المحفظة الافتراضية لهذا النوع
      if (!walletId) {
        const defaultWallet = db.prepare(`
          SELECT id FROM payment_wallets 
          WHERE type = ? AND is_default = 1 AND is_active = 1
          LIMIT 1
        `).get(walletType);
        if (defaultWallet) {
          walletId = defaultWallet.id;
        }
      }

      // تحديث رصيد المحفظة المحددة
      if (walletId && walletBalances[walletId]) {
        const amount = Number(tx.amount || 0);
        if (tx.kind === 'in') {
          walletBalances[walletId].balance += amount;
          // ✅ مبيعات قطع الغيار per wallet_id
          if (tx.ref && tx.ref.startsWith('repair_part_sale_')) {
            walletBalances[walletId].sales += amount;
          }
        } else if (tx.kind === 'out') {
          walletBalances[walletId].balance -= amount;
        }
      }
    });

    // ✅ حساب عدد الحركات الفعلية (مبيعات + ledger transactions) بعد آخر تقفيل
    let txCountQuery, txCountParams;
    if (afterTime) {
      txCountQuery = `SELECT COUNT(*) as cnt FROM cash_ledger WHERE datetime(created_at) > datetime(?) ${userFilterSQLNoAlias}`;
      txCountParams = [afterTime, ...userFilterParams];
    } else {
      txCountQuery = `SELECT COUNT(*) as cnt FROM cash_ledger WHERE 1=1 ${userFilterSQLNoAlias}`;
      txCountParams = [...userFilterParams];
    }
    const transactionsCount = db.prepare(txCountQuery).get(...txCountParams)?.cnt || 0;

    // ✅ تحويل walletBalances إلى مصفوفة مع إضافة الأرصدة المجمعة حسب النوع للتوافق العكسي
    const walletsArray = Object.values(walletBalances);
    
    // حساب الأرصدة المجمعة حسب النوع (للتوافق العكسي)
    const walletsByType = { cash: 0, mobile_wallet: 0, bank: 0 };
    walletsArray.forEach(w => {
      if (w.type === 'cash') walletsByType.cash += w.balance;
      else if (w.type === 'mobile_wallet') walletsByType.mobile_wallet += w.balance;
      else if (w.type === 'bank') walletsByType.bank += w.balance;
    });

    console.log('[DRAWER-WALLETS] ========== FINAL RESULT ==========');
    console.log('[DRAWER-WALLETS] Wallets FINAL (with sales):', walletsArray.map(w => `${w.name}: balance=${w.balance}, sales=${w.sales}`));
    console.log('[DRAWER-WALLETS] Wallets by Type (backward compatibility):', walletsByType);
    
    // إرجاع البيانات مع دعم التوافق العكسي
    return json({
      wallets: walletsArray, // جميع المحافظ الفعلية
      transactions_count: transactionsCount, // عدد الحركات في الدرج
      cash: walletsByType.cash, // للتوافق العكسي
      mobile_wallet: walletsByType.mobile_wallet, // للتوافق العكسي
      bank: walletsByType.bank // للتوافق العكسي
    });
  } catch (error) {
    console.error('[DRAWER-WALLETS] Error:', error);
    return err('فشل جلب أرصدة المحافظ', 500);
  }
}

// GET /wallet-balance - رصيد محفظة معينة في درج الكاش
if (route === 'wallet-balance' && req.method === 'GET') {
  const authCheck = requireAuth(req, route);
  if (!authCheck.authorized) return err(authCheck.error, authCheck.code);

  try {
    const walletType = url.searchParams.get('type') || 'cash';
    console.log('[WALLET-BALANCE] Requested wallet type:', walletType);
    const today = new Date().toISOString().split('T')[0];

    // جلب مبيعات اليوم لهذه المحفظة
    let salesTotal = 0;

    // مبيعات الأجهزة
    const deviceSales = db.prepare(`
      SELECT COALESCE(SUM(paid_now), 0) as total
      FROM sales
      WHERE date(created_at) = ?
        AND status = 'completed'
        AND payment_method = ?
    `).get(today, walletType === 'mobile_wallet' ? 'mobile_wallet' : walletType === 'bank' ? 'bank' : 'cash');
    salesTotal += deviceSales?.total || 0;

    // مبيعات الإكسسوارات
    const accessorySales = db.prepare(`
      SELECT COALESCE(SUM(total_price), 0) as total
      FROM accessory_movements
      WHERE date(created_at) = ?
        AND type = 'sale'
        AND payment_method = ?
    `).get(today, walletType === 'mobile_wallet' ? 'mobile_wallet' : walletType === 'bank' ? 'bank' : 'cash');
    salesTotal += accessorySales?.total || 0;

    // جلب عمليات cash_ledger لهذه المحفظة - دعم wallet_id و wallet_type
    // Get wallet IDs for this type
    const walletIds = db.prepare(`
      SELECT id FROM payment_wallets WHERE type = ? AND is_active = 1
    `).all(walletType).map(w => w.id);
    
    let ledgerInQuery = `
      SELECT COALESCE(SUM(amount), 0) as total
      FROM cash_ledger
      WHERE date(created_at) = ?
        AND kind = 'in'
        AND (
          wallet_id IN (${walletIds.length > 0 ? walletIds.map(() => '?').join(',') : 'NULL'})
          OR (wallet_id IS NULL AND (wallet_type = ? OR (wallet_type IS NULL AND ? = 'cash')))
        )
    `;
    const ledgerInParams = walletIds.length > 0 ? [today, ...walletIds, walletType, walletType] : [today, walletType, walletType];
    const ledgerIn = db.prepare(ledgerInQuery).get(...ledgerInParams);

    let ledgerOutQuery = `
      SELECT COALESCE(SUM(amount), 0) as total
      FROM cash_ledger
      WHERE date(created_at) = ?
        AND kind = 'out'
        AND (
          wallet_id IN (${walletIds.length > 0 ? walletIds.map(() => '?').join(',') : 'NULL'})
          OR (wallet_id IS NULL AND (wallet_type = ? OR (wallet_type IS NULL AND ? = 'cash')))
        )
    `;
    const ledgerOutParams = walletIds.length > 0 ? [today, ...walletIds, walletType, walletType] : [today, walletType, walletType];
    const ledgerOut = db.prepare(ledgerOutQuery).get(...ledgerOutParams);

    const balance = salesTotal + (ledgerIn?.total || 0) - (ledgerOut?.total || 0);
    console.log('[WALLET-BALANCE] Result:', { walletType, salesTotal, ledgerIn: ledgerIn?.total, ledgerOut: ledgerOut?.total, balance });

    return json({ balance, wallet_type: walletType });
  } catch (error) {
    console.error('[WALLET-BALANCE] Error:', error);
    return err('فشل جلب رصيد المحفظة: ' + error.message, 500);
  }
}

// GET /dashboard-extra-profits - عمولات التحويلات + أرباح صافية إضافية لفترة محددة
if (route === 'dashboard-extra-profits' && req.method === 'GET') {
  try {
    const url = new URL(req.url, `http://${req.headers.host}`);
    const from = url.searchParams.get('from');
    const to = url.searchParams.get('to');

    // عمولات التحويلات من cash_ledger
    let commQuery = `SELECT COALESCE(SUM(amount), 0) as total FROM cash_ledger WHERE ref LIKE 'money_transfer_commission_%' AND kind = 'in'`;
    const commParams = [];
    if (from) { commQuery += ` AND date(created_at) >= date(?)`; commParams.push(from); }
    if (to) { commQuery += ` AND date(created_at) <= date(?)`; commParams.push(to); }
    const commissions = Number(db.prepare(commQuery).get(...commParams)?.total || 0);

    // أرباح صافية إضافية من safe_transactions (إيداعات من نوع "ربح صافي")
    let profitQuery = `SELECT COALESCE(SUM(amount), 0) as total FROM safe_transactions WHERE type = 'deposit' AND category = 'ربح صافي'`;
    const profitParams = [];
    if (from) { profitQuery += ` AND date(created_at) >= date(?)`; profitParams.push(from); }
    if (to) { profitQuery += ` AND date(created_at) <= date(?)`; profitParams.push(to); }
    const extraProfits = Number(db.prepare(profitQuery).get(...profitParams)?.total || 0);

    return json({
      transfer_commissions: commissions,
      extra_profits: extraProfits,
      total: commissions + extraProfits
    });
  } catch (error) {
    console.error('[DASHBOARD] Error getting extra profits:', error);
    return json({ transfer_commissions: 0, extra_profits: 0, total: 0 });
  }
}

// GET /main-safe-balance - رصيد الخزنة الرئيسية (إجمالي كل المحافظ)
if (route === 'main-safe-balance' && req.method === 'GET') {
  try {
    const inSum = db.prepare(`
      SELECT COALESCE(SUM(amount), 0) as total
      FROM safe_transactions
      WHERE type IN ('deposit','sale')
    `).get().total || 0;

    // ✅ FIX: إضافة 'transfer' للمصروفات - التحويلات من الدرج (مثل تحويلات فودافون)
    // بدون 'transfer' كان المبلغ المحول لا يُطرح من الرصيد
    const outSum = db.prepare(`
      SELECT COALESCE(SUM(amount), 0) as total
      FROM safe_transactions
      WHERE type IN ('withdrawal','purchase','expense','transfer')
    `).get().total || 0;

    const balance = inSum - outSum;
    return json({ balance });
  } catch (error) {
    console.error('[SAFE] Error getting balance:', error);
    return err('فشل جلب رصيد الخزنة', 500);
  }
}

// GET /general-accounts-summary - ملخص الحسابات العامة
if (route === 'general-accounts-summary' && req.method === 'GET') {
  try {
    const authCheck = requireAuth(req, route);
    if (!authCheck.authorized) return err(authCheck.error, authCheck.code);

    // ═══════════════════════════════════════════════════════════════
    // حساب إجمالي رصيد العملاء
    // ═══════════════════════════════════════════════════════════════
    const totalClientsBalance = db.prepare(`
      SELECT COALESCE(SUM(
        (
          -- ديون الأجهزة
          COALESCE(
            (SELECT SUM(
              CASE
                WHEN s.status = 'completed' THEN (s.sell_price - s.discount - s.paid_now)
                WHEN s.status = 'returned' THEN -(s.refund_amount - s.paid_now)
                WHEN s.status = 'cancelled' THEN 0
                ELSE 0
              END
            )
             FROM sales s
             WHERE s.client_id = c.id
            ), 0
          )
          +
          -- ديون الإكسسوارات
          COALESCE(
            (SELECT SUM(am.total_price - am.paid_amount)
             FROM accessory_movements am
             WHERE am.client_id = c.id AND am.type = 'sale' AND (am.total_price - am.paid_amount) > 0
            ), 0
          )
          -
          -- المدفوعات من safe_transactions
          COALESCE(
            (SELECT SUM(st.amount)
             FROM safe_transactions st
             WHERE st.reference_type = 'client_payment' AND st.reference_id = c.id
            ), 0
          )
          -
          -- المدفوعات من cash_ledger (القديمة)
          COALESCE(
            (SELECT SUM(cl.amount)
             FROM cash_ledger cl
             WHERE cl.kind = 'in' AND cl.ref = 'client_payment_' || c.id
            ), 0
          )
        )
      ), 0) as total
      FROM clients c
    `).get().total || 0;

    // ═══════════════════════════════════════════════════════════════
    // حساب إجمالي رصيد الموردين
    // ═══════════════════════════════════════════════════════════════
    const totalSuppliersBalance = db.prepare(`
      SELECT COALESCE(SUM(balance), 0) as total
      FROM suppliers
    `).get().total || 0;

    // ═══════════════════════════════════════════════════════════════
    // حساب إجمالي رصيد الخزنة
    // ═══════════════════════════════════════════════════════════════
    const safeInSum = db.prepare(`
      SELECT COALESCE(SUM(amount), 0) as total
      FROM safe_transactions
      WHERE type IN ('deposit','sale')
    `).get().total || 0;

    // ✅ FIX: إضافة 'transfer' للمصروفات - التحويلات من الدرج (مثل تحويلات فودافون)
    // بدون 'transfer' كان المبلغ المحول لا يُطرح من رصيد الخزنة في الحسابات العامة
    const safeOutSum = db.prepare(`
      SELECT COALESCE(SUM(amount), 0) as total
      FROM safe_transactions
      WHERE type IN ('withdrawal','purchase','expense','transfer')
    `).get().total || 0;

    const totalSafeBalance = safeInSum - safeOutSum;

    // ═══════════════════════════════════════════════════════════════
    // حساب إجمالي رصيد الشركاء (الاستثمارات - السحوبات + الأرباح المستحقة)
    // ═══════════════════════════════════════════════════════════════
    const partnersData = db.prepare(`
      SELECT 
        COALESCE(SUM(investment_amount), 0) as total_investment,
        COALESCE(SUM(total_withdrawals), 0) as total_withdrawals,
        COALESCE(SUM(profit_share_devices), 0) as total_profit_devices,
        COALESCE(SUM(profit_share_accessories), 0) as total_profit_accessories
      FROM partners
      WHERE status = 'active'
    `).get();

    const totalPartnersBalance = (partnersData.total_investment || 0) 
      - (partnersData.total_withdrawals || 0)
      + (partnersData.total_profit_devices || 0)
      + (partnersData.total_profit_accessories || 0);

    // ═══════════════════════════════════════════════════════════════
    // إحصائيات العدد
    // ═══════════════════════════════════════════════════════════════
    const clientsCount = db.prepare(`SELECT COUNT(*) as count FROM clients`).get().count || 0;
    const suppliersCount = db.prepare(`SELECT COUNT(*) as count FROM suppliers`).get().count || 0;
    const partnersCount = db.prepare(`SELECT COUNT(*) as count FROM partners WHERE status = 'active'`).get().count || 0;

    // ═══════════════════════════════════════════════════════════════
    // جلب قائمة العملاء مع الأرصدة (أعلى 50)
    // ═══════════════════════════════════════════════════════════════
    const clients = db.prepare(`
      SELECT
        c.id,
        c.name,
        c.phone,
        (
          COALESCE(
            (SELECT SUM(
              CASE
                WHEN s.status = 'completed' THEN (s.sell_price - s.discount - s.paid_now)
                WHEN s.status = 'returned' THEN -(s.refund_amount - s.paid_now)
                WHEN s.status = 'cancelled' THEN 0
                ELSE 0
              END
            )
             FROM sales s
             WHERE s.client_id = c.id
            ), 0
          )
          +
          COALESCE(
            (SELECT SUM(am.total_price - am.paid_amount)
             FROM accessory_movements am
             WHERE am.client_id = c.id AND am.type = 'sale' AND (am.total_price - am.paid_amount) > 0
            ), 0
          )
          -
          COALESCE(
            (SELECT SUM(st.amount)
             FROM safe_transactions st
             WHERE st.reference_type = 'client_payment' AND st.reference_id = c.id
            ), 0
          )
          -
          COALESCE(
            (SELECT SUM(cl.amount)
             FROM cash_ledger cl
             WHERE cl.kind = 'in' AND cl.ref = 'client_payment_' || c.id
            ), 0
          )
        ) as balance
      FROM clients c
      WHERE (
        COALESCE(
          (SELECT SUM(
            CASE
              WHEN s.status = 'completed' THEN (s.sell_price - s.discount - s.paid_now)
              WHEN s.status = 'returned' THEN -(s.refund_amount - s.paid_now)
              WHEN s.status = 'cancelled' THEN 0
              ELSE 0
            END
          )
           FROM sales s
           WHERE s.client_id = c.id
          ), 0
        )
        +
        COALESCE(
          (SELECT SUM(am.total_price - am.paid_amount)
           FROM accessory_movements am
           WHERE am.client_id = c.id AND am.type = 'sale' AND (am.total_price - am.paid_amount) > 0
          ), 0
        )
        -
        COALESCE(
          (SELECT SUM(st.amount)
           FROM safe_transactions st
           WHERE st.reference_type = 'client_payment' AND st.reference_id = c.id
          ), 0
        )
        -
        COALESCE(
          (SELECT SUM(cl.amount)
           FROM cash_ledger cl
           WHERE cl.kind = 'in' AND cl.ref = 'client_payment_' || c.id
          ), 0
        )
      ) != 0
      ORDER BY ABS(balance) DESC
      LIMIT 50
    `).all();

    // ═══════════════════════════════════════════════════════════════
    // جلب قائمة الموردين مع الأرصدة (أعلى 50)
    // ═══════════════════════════════════════════════════════════════
    const suppliers = db.prepare(`
      SELECT id, name, phone, balance
      FROM suppliers
      WHERE balance != 0
      ORDER BY ABS(balance) DESC
      LIMIT 50
    `).all();

    // ═══════════════════════════════════════════════════════════════
    // جلب قائمة الشركاء
    // ═══════════════════════════════════════════════════════════════
    const partners = db.prepare(`
      SELECT 
        id,
        name,
        phone,
        investment_amount,
        total_withdrawals,
        profit_share_devices,
        profit_share_accessories,
        (investment_amount - total_withdrawals + profit_share_devices + profit_share_accessories) as balance
      FROM partners
      WHERE status = 'active'
      ORDER BY ABS(balance) DESC
    `).all();

    // ═══════════════════════════════════════════════════════════════
    // جلب محافظ الخزنة
    // ═══════════════════════════════════════════════════════════════
    const wallets = db.prepare(`
      SELECT 
        id,
        name,
        type,
        is_default,
        is_active
      FROM payment_wallets
      WHERE is_active = 1
      ORDER BY type, is_default DESC, name
    `).all();

    const walletsWithBalance = wallets.map(wallet => {
      const walletId = wallet.id;
      const walletType = wallet.type;
      
      const deposits = db.prepare(`
        SELECT COALESCE(SUM(amount), 0) total
        FROM safe_transactions
        WHERE type IN ('deposit','sale')
        AND (wallet_id = ? OR (wallet_id IS NULL AND wallet_type = ?))
      `).get(walletId, walletType).total || 0;

      const withdrawals = db.prepare(`
        SELECT COALESCE(SUM(amount), 0) total
        FROM safe_transactions
        WHERE type IN ('withdrawal','purchase','expense','transfer')
        AND (wallet_id = ? OR (wallet_id IS NULL AND wallet_type = ?))
      `).get(walletId, walletType).total || 0;

      const incomingTransfers = db.prepare(`
        SELECT COALESCE(SUM(amount), 0) total
        FROM safe_transactions
        WHERE type = 'transfer' AND target_wallet = ?
      `).get(walletType).total || 0;

      return {
        ...wallet,
        balance: deposits - withdrawals + incomingTransfers
      };
    });

    return json({
      success: true,
      summary: {
        totalClientsBalance,
        totalSuppliersBalance,
        totalSafeBalance,
        totalPartnersBalance,
        clientsCount,
        suppliersCount,
        partnersCount
      },
      clients,
      suppliers,
      partners,
      safeWallets: walletsWithBalance
    });
  } catch (error) {
    console.error('[GENERAL_ACCOUNTS] Error getting summary:', error);
    return err('فشل جلب ملخص الحسابات العامة: ' + error.message, 500);
  }
}

